INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tutoria', 'bachillerato', '{1}', 'El síndrome del impostor', 'Muchos estudiantes brillantes que acceden a Bachillerato experimentan el llamado síndrome del impostor: la sensación persistente de no merecer sus logros y de que, tarde o temprano, los demás descubrirán que son un fraude. Esta distorsión cognitiva, descrita por las psicólogas Pauline Clance y Suzanne Imes en 1978, afecta con especial frecuencia a quienes obtienen buenas calificaciones y se mueven en entornos competitivos. Quien lo sufre tiende a atribuir sus éxitos a la suerte, a la facilidad del examen o a la benevolencia del profesorado, en lugar de a su propio esfuerzo y capacidad. Paradójicamente, este pensamiento no desaparece con los nuevos logros, sino que se refuerza: cuanto más alto se llega, mayor es el miedo a caer. Los especialistas recomiendan varias estrategias para combatirlo. La primera consiste en llevar un registro escrito de los logros objetivos, revisándolo cuando aparezcan las dudas. La segunda es compartir estas inquietudes con compañeros de confianza, porque descubrir que otros sienten lo mismo reduce el aislamiento. La tercera implica sustituir el perfeccionismo por la noción de suficiencia: no todo trabajo debe alcanzar la excelencia absoluta. Finalmente, aceptar los elogios sin minimizarlos constituye un ejercicio sencillo pero poderoso. Entender que el síndrome del impostor es habitual, sobre todo en alumnado de alto rendimiento, permite desdramatizarlo y afrontar el Bachillerato con una autoimagen más equilibrada.', '[{"pregunta":"¿Quién describió por primera vez el síndrome del impostor?","opciones":["Sigmund Freud en 1920","Clance e Imes en 1978","Daniel Goleman en 1995","Carl Jung en 1950"],"correcta":1},{"pregunta":"¿A qué suelen atribuir sus éxitos quienes sufren este síndrome?","opciones":["A su esfuerzo personal","A factores externos como la suerte","A la inteligencia innata","A sus contactos sociales"],"correcta":1},{"pregunta":"Según el texto, una estrategia útil es:","opciones":["Evitar hablar del tema","Llevar un registro escrito de los logros","Renunciar a retos exigentes","Buscar entornos sin competencia"],"correcta":1},{"pregunta":"¿Qué paradoja señala el texto?","opciones":["Que el síndrome desaparece con el éxito","Que el síndrome se refuerza con los nuevos logros","Que solo afecta a personas mediocres","Que es exclusivo de los adultos"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'El método Cornell para tomar apuntes', 'El sistema Cornell, diseñado por Walter Pauk en la Universidad de Cornell durante los años cincuenta, continúa siendo una de las técnicas de estudio más recomendadas para Bachillerato y educación superior. Su eficacia reside en la estructura que impone al folio: una columna estrecha a la izquierda reservada para palabras clave o preguntas, una columna ancha a la derecha para los apuntes propiamente dichos y una franja inferior destinada al resumen. Durante la clase, el alumnado solo escribe en la columna ancha, anotando ideas principales, ejemplos y explicaciones con frases cortas. Al terminar la sesión, dedica unos minutos a rellenar la columna izquierda con palabras gancho o preguntas que evoquen el contenido. Finalmente, antes de acostarse o al día siguiente, redacta en la franja inferior un resumen de tres o cuatro líneas que sintetice lo fundamental. La fuerza del método radica en que obliga a revisar el contenido tres veces muy próximas en el tiempo, aprovechando la llamada curva del olvido descrita por Ebbinghaus. Además, la columna de preguntas permite autoevaluarse tapando los apuntes y respondiendo de memoria, lo que se conoce como evocación activa. Numerosos estudios muestran que esta técnica supera en resultados a la simple relectura. Su principal inconveniente es que exige disciplina inicial, pero quienes lo mantienen durante varias semanas rara vez lo abandonan.', '[{"pregunta":"¿Dónde y cuándo se diseñó el método Cornell?","opciones":["En Harvard en los años cuarenta","En Cornell en los años cincuenta","En Oxford en los años sesenta","En el MIT en los años setenta"],"correcta":1},{"pregunta":"¿Qué se escribe en la franja inferior del folio?","opciones":["Las fórmulas matemáticas","Un resumen de tres o cuatro líneas","Preguntas del examen","La bibliografía consultada"],"correcta":1},{"pregunta":"¿Con qué fenómeno psicológico conecta este método?","opciones":["El efecto Dunning-Kruger","La curva del olvido de Ebbinghaus","La disonancia cognitiva","El sesgo de confirmación"],"correcta":1},{"pregunta":"Según el texto, la técnica supera en resultados a:","opciones":["La escucha pasiva","La simple relectura","El subrayado","Los mapas conceptuales"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Higiene del sueño en Bachillerato', 'La etapa de Bachillerato coincide con un retraso fisiológico del reloj biológico adolescente: la melatonina empieza a segregarse más tarde, lo que dificulta conciliar el sueño antes de medianoche. Paradójicamente, los horarios escolares siguen siendo muy tempranos, de modo que el alumnado acumula una deuda de sueño semanal que trata de compensar los fines de semana durmiendo hasta mediodía. Este patrón, llamado jet lag social, desajusta aún más el ritmo circadiano y deteriora el rendimiento cognitivo. Las recomendaciones de los especialistas se basan en crear condiciones estables. En primer lugar, conviene mantener horarios de acostarse y levantarse con variaciones inferiores a una hora entre días lectivos y festivos. En segundo lugar, la luz azul de pantallas suprime la producción natural de melatonina, por lo que se aconseja evitar móviles y ordenadores al menos sesenta minutos antes de dormir. En tercer lugar, la cafeína consumida después de las cuatro de la tarde permanece activa hasta ocho horas. También importa el entorno: una habitación oscura, silenciosa y a unos dieciocho grados favorece el sueño profundo. Dormir menos de siete horas durante la semana perjudica la consolidación de la memoria, proceso que ocurre precisamente en la fase REM. En un curso tan exigente académicamente, descuidar el sueño es sacrificar la herramienta que permite aprender y consolidar lo estudiado.', '[{"pregunta":"¿Qué ocurre con la melatonina en la adolescencia?","opciones":["Se segrega antes","Se segrega más tarde","Deja de producirse","Se duplica su cantidad"],"correcta":1},{"pregunta":"¿A qué se denomina jet lag social?","opciones":["Cambiar de país por estudios","Desajuste por dormir muy distinto entre semana y fin de semana","Falta de amigos","Trasnochar por redes sociales"],"correcta":1},{"pregunta":"¿Cuánto antes de dormir conviene dejar las pantallas?","opciones":["Diez minutos","Treinta minutos","Sesenta minutos","Tres horas"],"correcta":2},{"pregunta":"¿En qué fase del sueño se consolida la memoria?","opciones":["Fase 1 ligera","Fase REM","Duermevela","Microsiestas"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'La técnica Feynman para estudiar', 'El físico estadounidense Richard Feynman, Premio Nobel en 1965, desarrolló una manera de estudiar que lleva su nombre y que hoy utilizan miles de estudiantes universitarios. La técnica parte de una idea sencilla pero poderosa: si no eres capaz de explicar un concepto con palabras llanas, es que en realidad no lo entiendes. El procedimiento consta de cuatro pasos. Primero, se elige un tema y se escribe su nombre en la parte superior de una hoja. Segundo, se redacta una explicación del contenido como si se estuviera dando clase a un niño de doce años, evitando tecnicismos y simplificando al máximo. Tercero, cuando aparecen lagunas o bloqueos, se regresa a los apuntes o al manual para cubrir las zonas oscuras, hasta poder explicarlas también en lenguaje sencillo. Cuarto, se revisa el texto eliminando la jerga que haya quedado y buscando analogías cotidianas. El método obliga al cerebro a reorganizar la información, pasar de la memoria reconocitiva a la memoria productiva y detectar las partes débiles antes del examen. Es especialmente útil en asignaturas con conceptos abstractos como física, filosofía o economía. Quienes lo practican con regularidad afirman reducir el tiempo total de estudio, porque identifican rápidamente lo que no saben. Su limitación principal es la incomodidad inicial: escribir como si se enseñara puede parecer artificial, pero es precisamente esa fricción la que consolida el aprendizaje.', '[{"pregunta":"¿En qué disciplina fue Premio Nobel Richard Feynman?","opciones":["Química","Literatura","Física","Medicina"],"correcta":2},{"pregunta":"¿En qué consiste el segundo paso de la técnica?","opciones":["Leer el libro en voz alta","Explicar el contenido como a un niño de doce años","Hacer un esquema visual","Copiar los apuntes"],"correcta":1},{"pregunta":"¿Qué tipo de memoria activa este método?","opciones":["Reconocitiva","Productiva","Sensorial","Procedimental"],"correcta":1},{"pregunta":"¿Cuál es su principal limitación según el texto?","opciones":["Exige material costoso","Resulta incómodo al principio","Solo sirve para matemáticas","Ocupa demasiado tiempo"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Ansiedad ante los exámenes', 'La ansiedad ante los exámenes es una respuesta adaptativa del organismo cuando percibe una situación de evaluación como amenazante. En dosis moderadas, mejora el rendimiento porque aumenta la atención, la memoria de trabajo y la motivación; sin embargo, cuando supera cierto umbral, produce el efecto contrario: bloqueos, fallos de recuperación e incluso síntomas físicos como taquicardia, sudoración o molestias digestivas. Esta relación fue descrita en 1908 por los psicólogos Robert Yerkes y John Dodson mediante una curva en forma de U invertida: tanto la activación baja como la excesiva perjudican el resultado. En Bachillerato, donde la presión académica se intensifica por la cercanía de la EBAU, reconocer los síntomas es el primer paso para manejarlos. Las estrategias se dividen en dos grupos. Las cognitivas apuntan a modificar los pensamientos catastrofistas mediante la reestructuración: sustituir afirmaciones como voy a suspender seguro por otras más realistas del tipo he estudiado lo suficiente para intentarlo. Las estrategias somáticas actúan sobre el cuerpo a través de la respiración diafragmática, la relajación muscular progresiva o el ejercicio aeróbico regular, que reduce los niveles de cortisol. Conviene evitar los remedios contraproducentes, como los estimulantes, las sustancias relajantes sin prescripción o las noches en blanco previas a la prueba. Si la ansiedad impide funcionar o aparece fuera del contexto de los exámenes, es importante pedir ayuda profesional.', '[{"pregunta":"¿Qué forma tiene la curva de Yerkes-Dodson?","opciones":["Lineal ascendente","U invertida","Exponencial","Circular"],"correcta":1},{"pregunta":"Las estrategias cognitivas consisten en:","opciones":["Hacer deporte intenso","Modificar los pensamientos catastrofistas","Tomar infusiones relajantes","Dormir más horas"],"correcta":1},{"pregunta":"¿Qué hormona reduce el ejercicio aeróbico?","opciones":["Cortisol","Melatonina","Insulina","Testosterona"],"correcta":0},{"pregunta":"¿Cuándo conviene pedir ayuda profesional?","opciones":["Siempre que aparezca ansiedad","Cuando impida funcionar o aparezca fuera de los exámenes","Solo si hay taquicardia","Nunca, se debe superar solo"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'El sesgo de confirmación', 'El sesgo de confirmación es la tendencia a buscar, interpretar y recordar la información de una forma que confirme nuestras creencias previas, descartando lo que las contradice. Fue estudiado sistemáticamente por el psicólogo británico Peter Wason en los años sesenta, y desde entonces ha sido replicado en innumerables experimentos. Este sesgo explica por qué dos personas pueden leer la misma noticia y extraer conclusiones opuestas: cada una repara en los datos que sostienen su punto de vista. En la era digital el problema se agudiza, porque los algoritmos de las redes sociales alimentan al usuario con contenidos similares a los que ya consume, creando las llamadas burbujas de filtro. Dentro de estas burbujas, las opiniones se radicalizan al no entrar en contacto con argumentos contrarios. Combatir el sesgo requiere un esfuerzo consciente. Una primera estrategia consiste en practicar el llamado abogado del diablo: buscar deliberadamente argumentos en contra de la propia posición antes de formarse una opinión. Una segunda es leer medios con líneas editoriales distintas, comparando cómo se cuenta un mismo suceso. Una tercera implica revisar las fuentes originales, en lugar de aceptar titulares o resúmenes. En el ámbito académico, el sesgo de confirmación afecta también al estudio: quien cree que algo será irrelevante tiende a saltárselo y luego lamenta no haberlo repasado. Reconocer esta trampa mental es parte del pensamiento crítico maduro.', '[{"pregunta":"¿Quién estudió sistemáticamente este sesgo?","opciones":["Peter Wason","Daniel Kahneman","Noam Chomsky","Albert Bandura"],"correcta":0},{"pregunta":"¿Qué son las burbujas de filtro?","opciones":["Juegos de pantalla","Entornos digitales donde solo se ve contenido afín","Técnicas de estudio","Sistemas de seguridad online"],"correcta":1},{"pregunta":"El ejercicio del abogado del diablo consiste en:","opciones":["Defender a un amigo","Buscar argumentos en contra de la propia postura","Imitar a un juez","Callar en los debates"],"correcta":1},{"pregunta":"¿Cómo afecta este sesgo al estudio?","opciones":["Hace saltarse lo que se considera irrelevante","Aumenta el tiempo dedicado","Mejora la memoria","Fomenta el subrayado"],"correcta":0}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Inteligencia emocional según Goleman', 'El periodista y psicólogo Daniel Goleman popularizó en 1995 el concepto de inteligencia emocional, basado en investigaciones previas de Peter Salovey y John Mayer. Su idea central es que el éxito personal y profesional depende tanto o más de la gestión de las emociones que del cociente intelectual tradicional. Goleman distingue cinco competencias básicas. La primera es el autoconocimiento, entendido como la capacidad de reconocer las propias emociones en el momento en que surgen. La segunda es la autorregulación, que permite controlar los impulsos sin reprimirlos del todo. La tercera es la motivación, la habilidad de dirigir las emociones hacia metas a largo plazo aplazando la gratificación inmediata. La cuarta es la empatía, que consiste en captar los sentimientos ajenos a través del lenguaje verbal y no verbal. La quinta es la habilidad social, que engloba la resolución de conflictos, la influencia y el trabajo en equipo. Lo interesante del modelo es que estas competencias se aprenden y entrenan a cualquier edad, no son rasgos fijos. Numerosos estudios sugieren que el alumnado con mayor inteligencia emocional obtiene mejores resultados académicos, sufre menos bullying y mantiene relaciones más estables. En Bachillerato, cuando la presión se intensifica y las decisiones vitales se acercan, cultivar estas competencias ayuda a afrontar el estrés, los conflictos de grupo y la incertidumbre sobre el futuro con mayor serenidad y eficacia.', '[{"pregunta":"¿Quién popularizó el concepto en 1995?","opciones":["Carl Rogers","Daniel Goleman","Abraham Maslow","Jean Piaget"],"correcta":1},{"pregunta":"¿Cuántas competencias básicas distingue el modelo?","opciones":["Tres","Cuatro","Cinco","Siete"],"correcta":2},{"pregunta":"La motivación se define como:","opciones":["Tener muchas ganas de algo","Dirigir las emociones hacia metas aplazando la gratificación","Estar siempre alegre","Hablar con elocuencia"],"correcta":1},{"pregunta":"Según el texto, estas competencias son:","opciones":["Rasgos fijos innatos","Habilidades aprendibles a cualquier edad","Exclusivas de los adultos","Hereditarias"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Pensamiento crítico y fake news', 'Las fake news, o noticias fabricadas con apariencia de veracidad, se propagan por redes sociales a una velocidad seis veces superior a la información contrastada, según un estudio del MIT publicado en Science en 2018. Su eficacia radica en apelar a emociones intensas, especialmente la indignación y el miedo, que multiplican los compartidos sin que el usuario llegue a leer el cuerpo de la noticia. El problema no afecta solo a la política: también hay bulos sanitarios, científicos y educativos. Desarrollar defensas mentales frente a ellos es una tarea ineludible del pensamiento crítico contemporáneo. Los expertos proponen un protocolo sencillo conocido como las cuatro verificaciones. Primero, comprobar la fuente: si no aparece medio, autor o fecha, desconfía. Segundo, buscar la noticia en otros canales reconocidos; si solo la publica un sitio, probablemente no sea fiable. Tercero, revisar las imágenes mediante búsqueda inversa en Google o TinEye, porque muchas fake news reciclan fotografías antiguas fuera de contexto. Cuarto, consultar webs especializadas en verificación, como Maldita o Newtral en España. A estos pasos conviene añadir una pausa emocional: si la noticia provoca rabia o euforia inmediatas, esperar antes de compartirla. La alfabetización mediática no es un lujo académico, sino una forma de ejercicio ciudadano responsable en un entorno informativo saturado y muchas veces malintencionado.', '[{"pregunta":"¿Cuánto más rápido circulan las fake news según el MIT?","opciones":["Dos veces","Cuatro veces","Seis veces","Diez veces"],"correcta":2},{"pregunta":"¿A qué emociones apelan con frecuencia?","opciones":["Ternura y nostalgia","Indignación y miedo","Tristeza y melancolía","Orgullo y satisfacción"],"correcta":1},{"pregunta":"¿Para qué sirve la búsqueda inversa de imágenes?","opciones":["Mejorar la calidad","Detectar fotos antiguas fuera de contexto","Traducir textos","Contactar con el autor"],"correcta":1},{"pregunta":"¿Qué webs de verificación se mencionan?","opciones":["BBC y CNN","Maldita y Newtral","Wikipedia y Google","Twitter y Facebook"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'El aprendizaje espaciado', 'El aprendizaje espaciado, o repetición distribuida, es una de las técnicas de estudio con más respaldo científico. Su origen se remonta a 1885, cuando el psicólogo alemán Hermann Ebbinghaus publicó sus experimentos sobre la llamada curva del olvido, demostrando que la memoria decae exponencialmente si no se refrescan los contenidos. La clave del método consiste en distribuir las sesiones de repaso en el tiempo en lugar de concentrarlas en un mismo día, como ocurre con el empolle de última hora. Cuanto mayor es el intervalo entre repasos y mayor el número de repeticiones, más resistente al olvido se vuelve el recuerdo. Aplicaciones modernas como Anki, Quizlet o Memrise implementan algoritmos que calculan automáticamente cuándo conviene volver a mostrar cada tarjeta, en función de si el usuario acertó o falló en la revisión anterior. En la práctica, un estudiante puede estudiar un tema en una hora, repasarlo un día después durante quince minutos, volver a él cuatro días más tarde y, finalmente, hacer un último repaso una semana antes del examen. Numerosas comparaciones muestran que este patrón retiene hasta un setenta por ciento más de información que el estudio masivo equivalente en horas totales. Su principal desventaja es que exige planificación a medio plazo: quien improvisa el estudio no puede aplicarlo. Por eso resulta tan útil empezar con los temarios el primer día del trimestre, no la víspera del examen.', '[{"pregunta":"¿Quién investigó la curva del olvido?","opciones":["Wilhelm Wundt","Hermann Ebbinghaus","Ivan Pavlov","Edward Thorndike"],"correcta":1},{"pregunta":"¿En qué año publicó sus experimentos?","opciones":["1850","1885","1900","1920"],"correcta":1},{"pregunta":"¿Qué aplicación se menciona que usa estos algoritmos?","opciones":["Instagram","Anki","Zoom","Spotify"],"correcta":1},{"pregunta":"¿Cuál es la principal limitación de esta técnica?","opciones":["Requiere pagar software","Exige planificación a medio plazo","Solo sirve para idiomas","Cansa demasiado"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'La elección de carrera universitaria', 'Elegir una carrera universitaria es una de las decisiones más importantes de la vida adulta temprana y, sin embargo, muchos estudiantes llegan al final de Bachillerato sin haber reflexionado de manera estructurada. Los orientadores recomiendan combinar tres criterios para acotar opciones: intereses, aptitudes y oportunidades. Los intereses son los temas que despiertan curiosidad espontánea, esos que te hacen abrir una pestaña cuando aparecen en redes. Las aptitudes son las capacidades demostradas en calificaciones, premios o proyectos extraescolares. Las oportunidades son las salidas profesionales realistas, incluyendo tasas de empleo, movilidad y posibles compatibilidades con el mercado laboral. Una carrera que encaja en los tres vértices es la elección ideal, aunque no siempre existe esa combinación perfecta. Conviene también evitar trampas clásicas. La primera es elegir guiándose solo por la nota de corte, buscando la carrera más prestigiosa a la que se pueda acceder, sin atender a la vocación. La segunda es seguir el camino de los amigos o los padres por comodidad. La tercera es descartar opciones por prejuicios profesionales, sin haber consultado a profesionales en activo. Los expertos sugieren hacer una lista corta de entre tres y cinco grados, visitar universidades en jornadas de puertas abiertas, hablar con alumnado actual y, si es posible, asistir a clases reales. La decisión debe tomarse con la cabeza fría y el calendario holgado, no en la semana de matriculación.', '[{"pregunta":"¿Qué tres criterios recomiendan combinar los orientadores?","opciones":["Dinero, fama y tiempo libre","Intereses, aptitudes y oportunidades","Familia, amigos y ciudad","Nota, plazo y precio"],"correcta":1},{"pregunta":"¿Qué son las aptitudes según el texto?","opciones":["Los gustos musicales","Capacidades demostradas en calificaciones y proyectos","Los hobbies","Los contactos familiares"],"correcta":1},{"pregunta":"¿Cuál es la primera trampa mencionada?","opciones":["Elegir guiándose solo por la nota de corte","Preguntar a los profesores","Visitar universidades","Hacer tests vocacionales"],"correcta":0},{"pregunta":"¿Cuántos grados recomiendan tener en la lista corta?","opciones":["Uno o dos","Entre tres y cinco","Diez","Más de quince"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'La asertividad madura', 'La asertividad adulta es el arte de expresar lo que se piensa, siente o necesita respetando al mismo tiempo los derechos de la otra persona. Se sitúa a medio camino entre dos extremos disfuncionales: la pasividad, que consiste en callar para evitar conflictos y acaba generando resentimiento, y la agresividad, que impone la propia voluntad pasando por encima del otro. Una persona asertiva no teme decir que no cuando procede, pero tampoco busca pelea por cualquier desacuerdo. Los psicólogos distinguen varios componentes del comportamiento asertivo. El verbal incluye frases claras en primera persona, como me gustaría que me avisases antes, en lugar de acusaciones en segunda persona del tipo nunca me avisas. El no verbal comprende el contacto visual directo, la postura erguida, el tono de voz firme pero no elevado y los gestos relajados. El elemento cognitivo implica creer en los propios derechos: el derecho a equivocarse, a cambiar de opinión, a no saber algo o a pedir tiempo. Existen técnicas concretas fáciles de practicar. El disco rayado consiste en repetir la petición con serenidad ante la insistencia ajena. El banco de niebla permite reconocer lo válido de una crítica sin ceder por completo. La asertividad positiva se ejercita elogiando sinceramente cuando corresponde. Todas ellas mejoran con la práctica y son especialmente útiles en Bachillerato, donde las relaciones sociales, el trabajo en grupo y los conflictos familiares exigen una comunicación madura.', '[{"pregunta":"¿Entre qué dos extremos se sitúa la asertividad?","opciones":["Empatía y egoísmo","Pasividad y agresividad","Introversión y extraversión","Razón y emoción"],"correcta":1},{"pregunta":"¿Cómo debe construirse la frase asertiva?","opciones":["Con acusaciones en segunda persona","En primera persona con mensajes propios","En tercera persona impersonal","Con preguntas retóricas"],"correcta":1},{"pregunta":"¿En qué consiste la técnica del disco rayado?","opciones":["Callar y asentir","Repetir la petición con serenidad","Gritar más fuerte","Cambiar de tema"],"correcta":1},{"pregunta":"El banco de niebla permite:","opciones":["Rechazar toda crítica","Reconocer lo válido de una crítica sin ceder del todo","Atacar al crítico","Ignorar al interlocutor"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Los mapas mentales', 'Los mapas mentales son una técnica de estudio visual popularizada por el educador británico Tony Buzan en los años setenta, aunque esquemas similares ya aparecen en manuscritos medievales. Se construyen partiendo de una idea central, situada en el corazón de la hoja, de la que irradian ramas principales hacia los conceptos asociados. Cada rama puede ramificarse en subramas más finas, formando una estructura arbórea que reproduce, según Buzan, la forma en que las neuronas establecen conexiones. Su ventaja principal es que aprovechan los dos hemisferios cerebrales: el izquierdo mediante palabras y números, y el derecho mediante colores, imágenes y relaciones espaciales. Esto facilita la memorización y permite captar de un vistazo la estructura global de un tema. Para elaborarlos correctamente se recomiendan varias pautas. Usar una sola palabra clave por rama, evitando frases largas que saturen el espacio. Emplear al menos tres colores distintos para distinguir categorías. Incluir pequeños dibujos o iconos que funcionen como anclajes visuales. Disponer la hoja en horizontal y dejar el centro despejado para ampliaciones. Los mapas mentales son especialmente útiles en fases tempranas del estudio, para construir una visión panorámica del tema antes de profundizar, y en fases finales, como resumen global para el repaso. Su limitación es que no sustituyen los apuntes detallados cuando el contenido requiere argumentación extensa, pero como complemento resultan extraordinariamente eficaces.', '[{"pregunta":"¿Quién popularizó los mapas mentales?","opciones":["Edward de Bono","Tony Buzan","Howard Gardner","Ken Robinson"],"correcta":1},{"pregunta":"¿Qué se sitúa en el corazón de la hoja?","opciones":["El autor del mapa","La idea central","El índice","La bibliografía"],"correcta":1},{"pregunta":"¿Cuántos colores mínimos se recomiendan?","opciones":["Uno","Dos","Al menos tres","Al menos siete"],"correcta":2},{"pregunta":"¿En qué fases son más útiles?","opciones":["Solo durante el examen","En fases tempranas y finales del estudio","Nunca","Solo al copiar apuntes"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Redes sociales y salud mental', 'Un metaanálisis publicado en 2022 por la Universidad de Swansea recopiló datos de más de doscientos mil adolescentes y concluyó que existe una asociación moderada entre el uso intensivo de redes sociales y síntomas de ansiedad y depresión. La relación no es causal directa ni afecta a todo el mundo por igual, pero identifica varios mecanismos. El primero es la comparación social ascendente: al ver solo los momentos felices y los cuerpos editados de los demás, el cerebro concluye inconscientemente que la propia vida es peor. El segundo es el miedo a perderse algo, conocido por sus siglas FOMO, que empuja a revisar el móvil constantemente para no quedar fuera. El tercero es el desplazamiento de actividades saludables como el sueño, el deporte o las relaciones cara a cara. El uso nocturno resulta especialmente problemático, porque la luz azul altera el ritmo circadiano y los contenidos activadores impiden conciliar el sueño. Las recomendaciones de especialistas como Jean Twenge no consisten en abandonar las redes, algo poco realista, sino en desarrollar un uso consciente. Algunas estrategias eficaces son establecer límites de tiempo por aplicación, dejar el móvil fuera del dormitorio, eliminar notificaciones no esenciales, dejar de seguir cuentas que empeoren el ánimo y sustituirlas por contenidos informativos o creativos. Reflexionar cada semana sobre cómo te hace sentir el uso acumulado es un primer paso sencillo y revelador.', '[{"pregunta":"¿Cuántos adolescentes analizó el metaanálisis de Swansea?","opciones":["Diez mil","Cincuenta mil","Más de doscientos mil","Un millón"],"correcta":2},{"pregunta":"¿En qué consiste el fenómeno FOMO?","opciones":["Miedo a las multitudes","Miedo a perderse algo","Miedo escénico","Miedo a los exámenes"],"correcta":1},{"pregunta":"¿Por qué resulta problemático el uso nocturno?","opciones":["Consume más datos","La luz azul altera el ritmo circadiano","Gasta más batería","Los amigos están dormidos"],"correcta":1},{"pregunta":"¿Qué sugiere Jean Twenge?","opciones":["Abandonar las redes por completo","Desarrollar un uso consciente","Instalar más aplicaciones","Cambiar de teléfono"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'La gestión del tiempo y la matriz de Eisenhower', 'La matriz de Eisenhower es una herramienta de priorización atribuida al presidente estadounidense Dwight D. Eisenhower, quien afirmó que lo importante rara vez es urgente y lo urgente rara vez es importante. El consultor Stephen Covey popularizó la idea en su libro Los siete hábitos de la gente altamente efectiva. El método consiste en clasificar las tareas en un cuadrante de dos ejes: uno mide la importancia y otro la urgencia. El primer cuadrante, urgente e importante, recoge crisis o entregas inminentes, y debe atenderse de inmediato. El segundo, importante pero no urgente, contiene actividades como estudiar, hacer ejercicio o planificar; es el cuadrante estrella, donde se obtienen los mayores beneficios a largo plazo, pero al que se llega poco cuando se vive apagando fuegos. El tercero, urgente pero no importante, agrupa interrupciones, mensajes o reuniones que parecen prioritarias pero aportan poco; conviene delegarlas o reducirlas. El cuarto, ni urgente ni importante, incluye las actividades de puro entretenimiento improductivo, que deben limitarse. Aplicada a Bachillerato, la matriz revela que muchos estudiantes viven entre el primero y el cuarto cuadrante: estudian la víspera del examen y el resto del tiempo lo dedican al ocio digital. Quien consigue desplazar el peso de su semana hacia el segundo cuadrante reduce el estrés, mejora las notas y gana tiempo libre real, porque deja de vivir con la sensación permanente de ir con retraso.', '[{"pregunta":"¿A qué presidente se atribuye la idea original?","opciones":["Kennedy","Eisenhower","Lincoln","Roosevelt"],"correcta":1},{"pregunta":"¿Qué contiene el segundo cuadrante?","opciones":["Crisis inmediatas","Tareas importantes pero no urgentes","Interrupciones sin importancia","Entretenimiento puro"],"correcta":1},{"pregunta":"¿Quién popularizó la matriz en un famoso libro?","opciones":["Stephen Covey","Dale Carnegie","Tony Robbins","Brian Tracy"],"correcta":0},{"pregunta":"Según el texto, entre qué cuadrantes viven muchos estudiantes?","opciones":["Entre el segundo y el tercero","Entre el primero y el cuarto","Entre el segundo y el cuarto","Solo en el tercero"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Resiliencia y adversidad', 'La resiliencia es la capacidad humana de afrontar la adversidad, adaptarse y, en muchos casos, salir fortalecido de ella. El término procede de la física, donde designa la propiedad de un material que recupera su forma original tras ser deformado, y fue adoptado por la psicología en los años setenta gracias a investigaciones con niños y niñas en entornos de alto riesgo. Uno de los estudios pioneros lo realizó Emmy Werner en la isla de Kauai, donde siguió durante décadas a varios centenares de personas desde el nacimiento. Werner observó que un tercio de quienes habían crecido en condiciones muy adversas se convertían en adultos funcionales, e intentó identificar los factores protectores. Encontró varios recurrentes: la existencia de al menos un adulto de confianza, la participación en actividades estructuradas, un temperamento extrovertido y una narrativa positiva sobre los propios problemas. Los psicólogos actuales añaden otros elementos entrenables: la flexibilidad cognitiva, el sentido del humor, la capacidad de pedir ayuda, la regulación emocional y la búsqueda de significado. La resiliencia no es innata ni implica ausencia de sufrimiento: quien la posee también llora, se enfada o se derrumba, pero encuentra recursos para recomponerse. En Bachillerato, donde la vida empieza a presentar adversidades mayores como rupturas, duelos o fracasos académicos, cultivar esta capacidad resulta esencial. Conviene recordar que ningún trauma determina el futuro por sí solo: la manera de interpretarlo importa tanto como lo que ocurrió.', '[{"pregunta":"¿De qué ciencia procede el término resiliencia?","opciones":["Biología","Física","Química","Geología"],"correcta":1},{"pregunta":"¿Quién realizó el estudio en Kauai?","opciones":["Martin Seligman","Emmy Werner","Anna Freud","Mary Ainsworth"],"correcta":1},{"pregunta":"¿Qué fracción de niños en adversidad se volvían adultos funcionales?","opciones":["Un décimo","Un quinto","Un tercio","La mitad"],"correcta":2},{"pregunta":"Según el texto, la resiliencia:","opciones":["Es innata e inmodificable","No implica ausencia de sufrimiento","Exige no llorar jamás","Se hereda genéticamente"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Finanzas personales básicas', 'La educación financiera apenas aparece en los currículos oficiales, y muchos estudiantes llegan a la universidad o al primer empleo sin entender conceptos elementales. Conocer cuatro ideas básicas evita disgustos mayores durante la vida adulta. La primera es la diferencia entre ingresos, gastos y ahorro. El ahorro no es lo que queda a fin de mes, sino lo que se aparta al principio antes de gastar, siguiendo la regla páguese a sí mismo primero. La segunda idea es el interés compuesto, que Albert Einstein llamó la octava maravilla del mundo. Consiste en que los intereses generados pasan a formar parte del capital, produciendo nuevos intereses en el periodo siguiente. Así, pequeñas cantidades mantenidas durante décadas se transforman en sumas importantes sin necesidad de grandes aportaciones. La tercera idea es la del interés deudor negativo: las tarjetas revolving y los créditos rápidos aplican tipos que pueden superar el veinte por ciento anual, convirtiendo una compra pequeña en una deuda creciente difícil de saldar. La cuarta es la diversificación: no conviene concentrar todo el dinero en un único producto financiero ni en una única criptomoneda de moda. A estas ideas se añaden hábitos sencillos como llevar un registro mensual de ingresos y gastos, distinguir entre necesidades y caprichos, establecer un fondo de emergencia equivalente a tres meses de gastos y desconfiar de rentabilidades prometidas muy superiores a las de la banca tradicional.', '[{"pregunta":"¿Qué regla se menciona respecto al ahorro?","opciones":["Ahorrar lo que sobre","Páguese a sí mismo primero","Ahorrar solo en enero","Gastar todo cada mes"],"correcta":1},{"pregunta":"¿Cómo llamó Einstein al interés compuesto?","opciones":["La gran trampa","La octava maravilla del mundo","El mal necesario","La regla de oro"],"correcta":1},{"pregunta":"¿Qué tipo pueden superar las tarjetas revolving?","opciones":["Cinco por ciento","Diez por ciento","Veinte por ciento","Cincuenta por ciento"],"correcta":2},{"pregunta":"¿A cuántos meses de gastos equivale un fondo de emergencia recomendado?","opciones":["Uno","Tres","Seis","Doce"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'La ética digital y la huella online', 'Cada vez que navegamos, publicamos o reaccionamos en internet dejamos una huella digital que puede permanecer accesible durante décadas. Esta huella se divide en dos tipos. La huella activa está formada por el contenido que subimos voluntariamente: fotos, comentarios, publicaciones, vídeos. La huella pasiva son los datos que otros recogen sin que seamos plenamente conscientes: cookies, ubicaciones, historial de búsquedas, tiempo de visionado, contactos. Ambas alimentan perfiles comerciales usados por plataformas y anunciantes. Las implicaciones éticas son múltiples. Lo que un adolescente publica hoy puede aparecer en un proceso de selección laboral dentro de diez años, en una búsqueda de Google por parte de un compañero de universidad o en la admisión a un posgrado internacional. El llamado derecho al olvido, reconocido por la Unión Europea en 2014, permite solicitar la eliminación de resultados obsoletos en buscadores, pero el proceso es lento y no siempre eficaz. Los especialistas recomiendan aplicar dos filtros antes de publicar algo. El filtro temporal se formula preguntando si dentro de cinco años seguirás queriendo que ese contenido esté accesible. El filtro empático consiste en pensar si la persona a la que afecta se sentiría cómoda si viera esa publicación. Más allá de la prudencia personal, hay una dimensión ética colectiva: la cultura del contenido compartido se construye entre todos, y cada gesto de respeto o de crueldad suma. La etiqueta digital no es una moda, es una forma de ciudadanía.', '[{"pregunta":"¿Qué es la huella activa?","opciones":["Los datos que otros recogen sin permiso","El contenido que subimos voluntariamente","Las cookies del navegador","Los mensajes privados"],"correcta":1},{"pregunta":"¿En qué año se reconoció el derecho al olvido en la UE?","opciones":["2010","2012","2014","2018"],"correcta":2},{"pregunta":"¿En qué consiste el filtro temporal?","opciones":["Preguntarse si dentro de cinco años seguirás queriendo ese contenido accesible","Esperar cinco minutos","Publicar de noche","Revisar la ortografía"],"correcta":0},{"pregunta":"El filtro empático consiste en:","opciones":["Pedir permiso a los padres","Pensar si la persona afectada se sentiría cómoda","Consultar al profesor","Borrar después de un día"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'La motivación intrínseca', 'La psicología de la motivación distingue dos grandes fuentes: la extrínseca, que depende de recompensas o castigos externos, y la intrínseca, que surge del placer inherente a la actividad misma. Los investigadores Edward Deci y Richard Ryan formularon en los años ochenta la teoría de la autodeterminación, según la cual la motivación intrínseca florece cuando se satisfacen tres necesidades psicológicas básicas. La primera es la autonomía, entendida como la sensación de elegir lo que uno hace y de ser agente de la propia conducta. La segunda es la competencia, la percepción de estar haciendo algo que uno domina o puede llegar a dominar. La tercera es la relación, el vínculo significativo con otras personas. Cuando estas tres necesidades se cubren, el aprendizaje deja de ser una obligación pesada y se convierte en una experiencia absorbente, capaz de provocar estados de flujo como los que describe el psicólogo Mihály Csíkszentmihályi. Por el contrario, cuando la motivación es exclusivamente extrínseca basada en notas, premios o miedo al castigo, el efecto a medio plazo puede ser contraproducente: quien estudia solo por la nota pierde interés en cuanto esta deja de ser relevante. En Bachillerato, donde la carga académica es alta y el sentido del esfuerzo a veces se difumina, cultivar los elementos de autonomía, competencia y relación resulta decisivo. Conectar los temas con intereses personales, buscar niveles de dificultad adecuados y estudiar con amigos son maneras eficaces de reforzar la motivación duradera.', '[{"pregunta":"¿Quiénes formularon la teoría de la autodeterminación?","opciones":["Skinner y Watson","Deci y Ryan","Bandura y Rotter","Maslow y Rogers"],"correcta":1},{"pregunta":"¿Cuál NO es una de las tres necesidades básicas?","opciones":["Autonomía","Competencia","Relación","Riqueza"],"correcta":3},{"pregunta":"¿Quién describió los estados de flujo?","opciones":["Csíkszentmihályi","Seligman","Kahneman","Vygotsky"],"correcta":0},{"pregunta":"Según el texto, la motivación exclusivamente extrínseca:","opciones":["Es siempre lo mejor","Puede ser contraproducente a medio plazo","Produce flujo","Es gratis"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'Cómo hacer un trabajo de investigación', 'Los trabajos de investigación en Bachillerato inician al alumnado en metodologías que usará durante la universidad. El proceso puede parecer intimidante, pero se vuelve abordable cuando se divide en fases claras. La primera es la delimitación del tema: pasar de una idea vaga como la contaminación a una pregunta concreta como qué impacto tiene el tráfico en los niveles de dióxido de nitrógeno en el barrio del instituto. La segunda es la búsqueda bibliográfica, que hoy incluye fuentes tradicionales como libros o artículos, y recursos digitales como Google Scholar, Dialnet o repositorios universitarios. Es importante distinguir entre fuentes primarias, creadas durante el acontecimiento estudiado, y fuentes secundarias, que lo analizan posteriormente. La tercera fase es la elaboración de fichas o notas organizadas por temas, anotando siempre los datos bibliográficos completos para poder citarlos después. La cuarta es la redacción de un borrador con estructura clásica: introducción, desarrollo, conclusiones y bibliografía. Durante esta fase resulta fundamental evitar el plagio; citar las fuentes con un sistema coherente como APA, MLA o Chicago no es solo una exigencia académica sino una cuestión ética. La quinta fase es la revisión crítica, preferiblemente con un compañero o profesor. Finalmente, viene la presentación pública, que exige ensayar en voz alta, controlar el tiempo y anticipar las posibles preguntas. Un trabajo bien hecho no solo obtiene mejor calificación: desarrolla habilidades transferibles a cualquier futuro académico o laboral.', '[{"pregunta":"¿Cuál es la primera fase de un trabajo de investigación?","opciones":["La bibliografía","La delimitación del tema","La redacción","La presentación"],"correcta":1},{"pregunta":"¿Qué es una fuente primaria?","opciones":["Un libro de texto","Una fuente creada durante el acontecimiento estudiado","Wikipedia","Un periódico del siglo XX"],"correcta":1},{"pregunta":"¿Qué sistemas de citación se mencionan?","opciones":["APA, MLA o Chicago","BBC, CNN y TVE","HTML, CSS y JS","ESO, UE y ONU"],"correcta":0},{"pregunta":"Según el texto, citar las fuentes es:","opciones":["Solo una formalidad","Una cuestión ética","Opcional si copias poco","Solo para artículos extensos"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{1}', 'El efecto Dunning-Kruger', 'En 1999, los psicólogos David Dunning y Justin Kruger publicaron un artículo en el que describían un curioso sesgo cognitivo: las personas con menor competencia en un ámbito tienden a sobrestimar su capacidad, mientras que las más expertas, al tener una visión más completa del campo, suelen ser más prudentes al valorarse. El fenómeno, conocido desde entonces como efecto Dunning-Kruger, se representa con una curva que empieza alta en la llamada cima de la arrogancia, cae bruscamente hasta el valle de la desesperación cuando el aprendiz descubre cuánto ignora, y asciende después lentamente hacia la meseta de la sabiduría, donde el experto conoce sus fortalezas y limitaciones. El efecto aparece en casi todos los ámbitos: conducir, argumentar en política, juzgar películas, programar, debatir de nutrición. Su raíz está en que evaluar la propia competencia requiere, paradójicamente, tener cierta competencia. Quien no domina un campo carece de las herramientas necesarias para ver sus errores. En el ámbito educativo este sesgo explica por qué algunos estudiantes confiados suspenden y otros más dubitativos aprueban con nota. Las estrategias para combatirlo implican aceptar la retroalimentación de personas más experimentadas, comparar la propia producción con estándares externos, practicar la humildad epistémica y recordar la frase atribuida a Sócrates: solo sé que no sé nada. Conocer este efecto en Bachillerato, antes de enfrentarse a la universidad, es un buen antídoto frente a la sobreconfianza.', '[{"pregunta":"¿En qué año se publicó el estudio original?","opciones":["1989","1999","2009","2019"],"correcta":1},{"pregunta":"¿Qué ocurre con los más expertos según el efecto?","opciones":["Se sobrevaloran","Tienden a ser más prudentes al valorarse","No pueden medirse","Siempre fallan"],"correcta":1},{"pregunta":"¿Cómo se llama la primera fase de la curva?","opciones":["Valle de la desesperación","Cima de la arrogancia","Meseta de la sabiduría","Cuesta del esfuerzo"],"correcta":1},{"pregunta":"¿Qué frase se atribuye a Sócrates?","opciones":["Conócete a ti mismo","Solo sé que no sé nada","Pienso, luego existo","El hombre es la medida de todas las cosas"],"correcta":1}]'::jsonb);

