-- 2º BACHILLERATO (30 textos)
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tutoria', 'bachillerato', '{2}', 'La EBAU y las notas de corte', 'La Evaluación para el Bachillerato de Acceso a la Universidad, conocida como EBAU o EvAU según la comunidad autónoma, calcula la nota de admisión combinando dos elementos. El primero es la nota de acceso, que pondera un sesenta por ciento la media del expediente de Bachillerato y un cuarenta por ciento el resultado de la fase general del examen. La nota de acceso tiene un máximo de diez puntos y permite matricularse en cualquier grado si alcanza el corte correspondiente. A este resultado se suma la fase voluntaria específica, en la que el estudiante examina de materias extra escogidas estratégicamente en función de la carrera objetivo. Cada una de estas materias se multiplica por un parámetro de ponderación de cero punto uno, cero punto dos, hasta un máximo de cero punto dos, según la relevancia que cada universidad asigne a esa asignatura para ese grado. La suma de estas ponderaciones puede añadir hasta cuatro puntos, de modo que la nota de admisión final se sitúa en una escala de cero a catorce. Las notas de corte cambian cada año y dependen de la oferta de plazas y la demanda. Revisar las ponderaciones publicadas por cada universidad antes de elegir las asignaturas optativas de segundo es decisivo, porque una elección inteligente puede marcar la diferencia entre entrar o no en el grado deseado. Asimismo, conviene recordar que las notas de corte son indicativas: cada convocatoria es independiente.', '[{"pregunta":"¿Qué porcentaje pondera la media del expediente en la nota de acceso?","opciones":["Cuarenta por ciento","Cincuenta por ciento","Sesenta por ciento","Setenta por ciento"],"correcta":2},{"pregunta":"¿Cuál es la escala máxima de la nota de admisión final?","opciones":["Diez","Doce","Catorce","Dieciséis"],"correcta":2},{"pregunta":"¿Cuánto puede sumar cada asignatura de la fase voluntaria como máximo?","opciones":["Cero punto uno","Cero punto dos","Cero punto cinco","Uno"],"correcta":1},{"pregunta":"Según el texto, las notas de corte:","opciones":["Son fijas cada año","Dependen de la oferta y la demanda","Las pone el Ministerio","Coinciden con la media del alumnado"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Prepararse el último mes antes de la EBAU', 'El último mes antes de la EBAU es, probablemente, el más delicado del curso académico. Llegados a esta fase, la prioridad ya no es aprender contenidos nuevos sino consolidar los que se conocen y reducir errores evitables. Los orientadores recomiendan estructurar estas semanas en torno a tres ejes. El primero es el repaso activo: resolver exámenes reales de años anteriores en condiciones idénticas a la prueba, respetando el tiempo y sin consultar apuntes. Este entrenamiento familiariza al cerebro con el formato y detecta lagunas concretas. El segundo eje es la revisión selectiva: en lugar de releer el temario entero, se priorizan los temas más preguntados históricamente y aquellos en los que uno falla más. El tercer eje es el cuidado del cuerpo y la mente: dormir al menos siete horas, hacer ejercicio moderado diario, limitar cafeína y evitar el aislamiento. Un error frecuente es sacrificar el sueño en las últimas noches creyendo que así se estudia más; los estudios sobre memoria muestran justo lo contrario. El día previo al examen conviene dedicar un repaso ligero por la mañana, una actividad agradable por la tarde y un sueño reparador por la noche. Durante la prueba, conviene leer bien el enunciado, empezar por las preguntas dominadas, gestionar el tiempo con reloj y dejar los últimos minutos para revisar. Si aparece ansiedad intensa, respirar profundamente durante medio minuto suele devolver la claridad suficiente para continuar.', '[{"pregunta":"¿Cuál es la prioridad del último mes?","opciones":["Aprender contenidos nuevos","Consolidar y reducir errores","Descansar completamente","Cambiar de método"],"correcta":1},{"pregunta":"¿Qué consiste el repaso activo según el texto?","opciones":["Releer apuntes","Resolver exámenes reales en condiciones idénticas","Dictado en voz alta","Estudiar en grupo"],"correcta":1},{"pregunta":"¿Qué error frecuente se menciona sobre el sueño?","opciones":["Dormir demasiado","Sacrificar el sueño para estudiar más","Dormir con la luz encendida","Usar dos almohadas"],"correcta":1},{"pregunta":"¿Qué recomienda el texto si aparece ansiedad durante la prueba?","opciones":["Abandonar la sala","Respirar profundamente durante medio minuto","Pedir consejo al profesor","Beber café"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Las ramas de conocimiento universitarias', 'El sistema universitario español organiza los grados en cinco ramas de conocimiento, cada una con sus ponderaciones específicas en la fase voluntaria de la EBAU. La rama de Artes y Humanidades incluye carreras como Historia, Filología, Filosofía, Historia del Arte o Bellas Artes, y pondera materias como Latín, Griego, Literatura o Dibujo Artístico. La rama de Ciencias abarca Matemáticas, Física, Química, Biología, Geología o Ciencias del Mar, y pondera principalmente Matemáticas II, Física, Química y Biología. La rama de Ciencias de la Salud incluye Medicina, Enfermería, Fisioterapia, Farmacia, Odontología, Psicología y Nutrición; sus ponderaciones favorecen a Química, Biología, Matemáticas II y Física. La rama de Ciencias Sociales y Jurídicas es la más amplia: Derecho, Economía, Administración de Empresas, Magisterio, Periodismo, Sociología o Turismo. Pondera Matemáticas Aplicadas, Economía, Geografía o Historia. Finalmente, la rama de Ingeniería y Arquitectura agrupa ingenierías diversas y Arquitectura, con fuerte ponderación de Matemáticas II, Física y Dibujo Técnico. Al cambiar de rama durante los estudios universitarios se suelen perder créditos, por lo que conviene acertar desde el principio. Las pasarelas existen pero son limitadas. Informarse con orientadores, visitar facultades, hablar con antiguos alumnos y hacer test vocacionales reconocidos son pasos que ayudan a tomar una decisión informada y reducen el riesgo de abandono universitario, que en España sigue siendo alto en el primer curso.', '[{"pregunta":"¿Cuántas ramas de conocimiento existen?","opciones":["Tres","Cuatro","Cinco","Seis"],"correcta":2},{"pregunta":"¿En qué rama se sitúa Psicología?","opciones":["Humanidades","Ciencias","Ciencias de la Salud","Ingeniería"],"correcta":2},{"pregunta":"¿Qué materia pondera fuerte en Ingeniería y Arquitectura?","opciones":["Latín","Dibujo Técnico","Literatura","Filosofía"],"correcta":1},{"pregunta":"Según el texto, al cambiar de rama durante los estudios:","opciones":["Se mantienen todos los créditos","Se suelen perder créditos","Se reinicia el expediente","Se gana una beca extra"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Becas y ayudas al estudio universitario', 'El Ministerio de Universidades convoca cada año las principales becas estatales para cursar estudios superiores. La más conocida es la beca general del Ministerio, que cubre matrícula, residencia, transporte y material en cantidades variables según la renta familiar y los kilómetros entre el domicilio habitual y la universidad. Existen también becas específicas por rendimiento académico, como las becas Colabora que permiten trabajar como ayudante en departamentos, o las becas de movilidad Erasmus para cursar un cuatrimestre en otro país europeo. Junto a las estatales, las comunidades autónomas convocan ayudas complementarias, y muchas universidades ofrecen sus propias becas por excelencia académica, deportiva o artística. Existen además fundaciones privadas como La Caixa, BBVA, Rafael del Pino o Amancio Ortega, que financian estudios completos en España o en el extranjero a cambio, en ocasiones, de compromisos posteriores. Los requisitos más comunes combinan una nota mínima en Bachillerato, normalmente entre siete y ocho, con un umbral de renta familiar. Los plazos suelen abrirse entre marzo y junio, y es frecuente que los alumnos los pasen por alto al centrarse en la EBAU. Llevar un calendario con las fechas límite y preparar la documentación con antelación es una inversión que puede ahorrar miles de euros. Conviene también cruzar varias convocatorias: algunas son compatibles entre sí y otras excluyentes, de modo que revisar las bases evita sorpresas desagradables una vez firmada la matrícula.', '[{"pregunta":"¿Qué cubre la beca general del Ministerio?","opciones":["Solo la matrícula","Matrícula, residencia, transporte y material","Solo residencia","Únicamente libros"],"correcta":1},{"pregunta":"¿Qué son las becas Colabora?","opciones":["Becas Erasmus","Ayudas para trabajar como ayudante en departamentos","Ayudas familiares","Becas deportivas"],"correcta":1},{"pregunta":"¿Entre qué meses suelen abrirse los plazos?","opciones":["Enero y febrero","Marzo y junio","Agosto y septiembre","Octubre y noviembre"],"correcta":1},{"pregunta":"¿Qué fundaciones privadas se mencionan?","opciones":["La Caixa, BBVA, Rafael del Pino o Amancio Ortega","Gates y Rockefeller","Solo fundaciones universitarias","UNICEF y Cruz Roja"],"correcta":0}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La vida en una residencia universitaria', 'Trasladarse a una residencia o colegio mayor para estudiar en otra ciudad marca un punto de inflexión en la vida adulta. Por primera vez, muchas tareas que los adultos cercanos asumían pasan a ser responsabilidad propia: organizar las comidas, gestionar el presupuesto, mantener la habitación, conciliar horarios con compañeros de cuarto o de planta. Las residencias ofrecen un entorno estructurado con normas comunes, servicios de limpieza y comedor, lo que alivia algunas preocupaciones, pero exigen adaptación al reglamento y convivencia con personas de orígenes distintos. Los colegios mayores añaden una dimensión formativa con actividades culturales, deportivas y de voluntariado. Vivir en piso compartido con otros estudiantes ofrece más autonomía y suele ser más económico, pero aumenta la carga organizativa: compras, turnos de limpieza, facturas, conflictos sobre el ruido o las visitas. Los orientadores recomiendan varias pautas para la primera experiencia fuera de casa. Conviene establecer desde el principio reglas claras con los compañeros sobre limpieza, pago de suministros y horarios de descanso. También ayuda mantener rutinas básicas como el sueño regular y las comidas en horas fijas, porque la ausencia de supervisión facilita descontrolarse. Es importante cultivar la red social local sin aislarse y, al mismo tiempo, mantener contacto regular con la familia sin depender emocionalmente de cada llamada. Finalmente, pedir ayuda en servicios universitarios si aparecen problemas de adaptación o tristeza persistente no es un signo de debilidad, sino de madurez.', '[{"pregunta":"¿Qué añaden los colegios mayores según el texto?","opciones":["Solo alojamiento","Una dimensión formativa con actividades culturales","Clases de repaso obligatorias","Alojamiento gratuito"],"correcta":1},{"pregunta":"¿Cuál es la ventaja principal de los pisos compartidos?","opciones":["Más supervisión","Más autonomía y economía","Mayor seguridad","Menos gestión"],"correcta":1},{"pregunta":"¿Qué recomienda el texto sobre la familia?","opciones":["Evitar todo contacto","Mantener contacto regular sin depender emocionalmente","Llamar cada hora","Regresar cada fin de semana"],"correcta":1},{"pregunta":"Pedir ayuda en servicios universitarios es signo de:","opciones":["Debilidad","Madurez","Fracaso","Falta de esfuerzo"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'El primer contrato de trabajo', 'Muchos estudiantes universitarios firman su primer contrato laboral durante la carrera o al acabarla, compatibilizando trabajo con estudios o emprendiendo su carrera profesional. Conocer los elementos básicos de un contrato evita abusos. Los contratos más habituales son el indefinido, pensado para puestos estables, y el temporal, limitado a causas justificadas como sustitución, acumulación de tareas o formación. La reforma laboral de 2022 endureció los requisitos para los contratos temporales y amplió el peso del indefinido. Todo contrato debe incluir datos identificativos, categoría profesional, funciones, jornada laboral, salario bruto, duración y periodo de prueba. El salario mínimo interprofesional establece el suelo legal por debajo del cual no se puede pagar. Los convenios colectivos sectoriales añaden condiciones específicas para cada rama y suelen mejorar los mínimos legales. Las vacaciones, treinta días naturales por año trabajado, no pueden sustituirse por dinero. Las horas extra deben pagarse o compensarse con descanso, y existen límites legales para protegerlas. Es importante conservar copia firmada del contrato, las nóminas mensuales y los partes de alta en la Seguridad Social, verificables en la web oficial mediante certificado digital. Antes de firmar, conviene revisar con calma, preguntar por cláusulas dudosas y, si hay dudas, consultar a un sindicato o al servicio jurídico universitario. Conocer los propios derechos no es desconfianza: es la forma más sana de construir una relación laboral equilibrada desde el primer día.', '[{"pregunta":"¿Qué tipos de contratos son los más habituales?","opciones":["Mercantil y civil","Indefinido y temporal","Freelance y becario","Parcial y virtual"],"correcta":1},{"pregunta":"¿Cuántos días de vacaciones naturales corresponden por año?","opciones":["Veinte","Veintidós","Treinta","Cuarenta"],"correcta":2},{"pregunta":"¿Qué reforma endureció los contratos temporales?","opciones":["La de 2012","La de 2018","La de 2022","La de 2024"],"correcta":2},{"pregunta":"Según el texto, antes de firmar conviene:","opciones":["Firmar rápido","Consultar dudas con un sindicato o servicio jurídico","Evitar hacer preguntas","No leer las cláusulas"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'El currículum en formato europeo', 'El currículum vítae es una síntesis estructurada de la trayectoria académica, profesional y personal de una persona, pensada para presentarse a procesos de selección. Existen varios modelos, pero el más extendido en Europa es el Europass, disponible de forma gratuita en la web de la Unión Europea. Su diseño es reconocible para cualquier empleador del continente y permite adjuntar certificados digitales verificados. Un buen currículum debe ser claro, conciso y adaptado al puesto concreto. Los expertos recomiendan limitarlo a una página para perfiles junior y dos como máximo para profesionales con más experiencia. Comienza con los datos personales y un titular profesional breve que resuma en una línea el perfil. Sigue la formación académica, indicando título, institución y fechas, en orden cronológico inverso. Después se listan las experiencias laborales, subrayando las funciones y los logros cuantificables siempre que sea posible, por ejemplo, incrementé las ventas en un quince por ciento. A continuación, se incluyen los idiomas con los niveles del Marco Común Europeo, las competencias digitales, los cursos relevantes y las aficiones si aportan valor. Conviene adaptar cada envío al puesto, destacando los aspectos más afines. Se deben evitar faltas de ortografía, fotos inadecuadas, datos irrelevantes y presentaciones sobrecargadas. Finalmente, acompañar el currículum con una carta de presentación breve y personalizada multiplica las posibilidades de pasar a entrevista, porque demuestra interés real por la empresa y no un envío masivo.', '[{"pregunta":"¿Cómo se llama el modelo europeo más extendido?","opciones":["Eurostat","Europass","Eurocopa","Euroweb"],"correcta":1},{"pregunta":"¿A cuántas páginas conviene limitar un CV junior?","opciones":["Una página","Dos páginas","Tres páginas","Cinco páginas"],"correcta":0},{"pregunta":"¿Cómo deben aparecer los logros profesionales?","opciones":["Solo cualitativos","Cuantificables cuando sea posible","Sin cifras","En forma de anécdotas"],"correcta":1},{"pregunta":"¿Qué debe acompañar al CV para mejorar resultados?","opciones":["Una recomendación familiar","Una carta de presentación personalizada","Un video tutorial","Un dibujo"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La entrevista de trabajo por competencias', 'La entrevista por competencias es la técnica de selección más extendida en empresas medianas y grandes. Parte del supuesto de que el comportamiento pasado predice el futuro: si alguien ha demostrado resiliencia en una situación difícil, probablemente volverá a hacerlo. El entrevistador no pregunta por cualidades abstractas, sino por situaciones concretas. Preguntas típicas son: cuéntame una vez en la que tuviste que liderar un equipo con un compañero difícil, o describe una ocasión en la que cometiste un error y cómo lo resolviste. Para responder a este tipo de preguntas los profesionales usan el método STAR, acrónimo de situación, tarea, acción y resultado. En situación se describe brevemente el contexto. En tarea se explica la responsabilidad o el reto concreto. En acción se detallan los pasos específicos que uno tomó, evitando hablar en plural genérico y usando siempre la primera persona del singular. Finalmente, en resultado se indica el impacto logrado, idealmente con alguna cifra o evaluación objetiva. El método obliga a estructurar la respuesta, evita divagaciones y demuestra capacidad reflexiva. Los expertos recomiendan llegar a la entrevista con al menos seis historias preparadas que ilustren competencias típicas: trabajo en equipo, resolución de conflictos, iniciativa, aprendizaje rápido, gestión del estrés y orientación al cliente. Estas historias deben ser reales, concretas y memorables. Dar vagas respuestas teóricas o idealizadas suele ser el principal motivo de fracaso en este formato de entrevista.', '[{"pregunta":"¿Qué supuesto fundamenta la entrevista por competencias?","opciones":["La intuición del entrevistador","Que el comportamiento pasado predice el futuro","Los tests psicométricos","La apariencia del candidato"],"correcta":1},{"pregunta":"¿Qué significa STAR?","opciones":["Simple, Tarea, Arte, Repetición","Situación, Tarea, Acción, Resultado","Silencio, Tiempo, Acción, Reflexión","Saludo, Tema, Actitud, Repaso"],"correcta":1},{"pregunta":"En qué persona conviene narrar las acciones?","opciones":["Plural genérico","Primera persona del singular","Tercera persona","Impersonal"],"correcta":1},{"pregunta":"¿Cuántas historias recomiendan llevar preparadas?","opciones":["Dos","Cuatro","Al menos seis","Más de veinte"],"correcta":2}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La marca personal en la era digital', 'El concepto de marca personal, popularizado por el consultor Tom Peters en un artículo de 1997 titulado La marca llamada tú, se refiere al conjunto de percepciones que los demás tienen sobre una persona en un ámbito determinado. En la era digital, construir una marca personal ya no es opcional para quienes buscan visibilidad profesional: cualquiera que escriba tu nombre en un buscador verá resultados que, en parte, hablan por ti. Gestionar esa imagen requiere una reflexión previa sobre qué valores, conocimientos o proyectos quieres asociar a tu nombre. El primer paso es decidir una línea temática coherente, evitando proyectar un mosaico caótico de opiniones y temas inconexos. El segundo es elegir dos o tres plataformas acordes con el público objetivo: LinkedIn para perfiles profesionales, GitHub para programadores, Behance para creativos, X para comunicadores, YouTube o TikTok para audiencias amplias. El tercer paso es crear contenido de calidad de forma regular, aunque sea sencillo: resúmenes de libros leídos, reflexiones sobre temas de estudio, proyectos personales, entrevistas a personas admiradas. El cuarto es interactuar con honestidad, huyendo del postureo vacío y del spam. Los errores típicos incluyen mostrar comportamientos contradictorios, participar en polémicas tóxicas o publicar impulsivamente sin pensar en las consecuencias a largo plazo. Una buena marca personal no se construye en un mes, sino a lo largo de años. La ventaja es que, una vez consolidada, abre puertas profesionales que ni siquiera se habían imaginado.', '[{"pregunta":"¿Quién popularizó el concepto de marca personal?","opciones":["Peter Drucker","Tom Peters","Seth Godin","Simon Sinek"],"correcta":1},{"pregunta":"¿En qué año apareció el artículo original?","opciones":["1987","1997","2007","2017"],"correcta":1},{"pregunta":"¿Qué plataforma se recomienda para programadores?","opciones":["TikTok","Behance","GitHub","LinkedIn"],"correcta":2},{"pregunta":"Según el texto, una marca personal:","opciones":["Se construye en un mes","Se construye a lo largo de años","No requiere constancia","Se compra en agencias"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La negociación colaborativa', 'El método de negociación colaborativa, desarrollado por los profesores Roger Fisher y William Ury en la Universidad de Harvard, revolucionó el modo en que se abordan los conflictos en los años ochenta. Su libro Obtenga el sí propuso cuatro principios que rompen con la negociación posicional tradicional, en la que cada parte defiende su postura rígidamente. El primer principio es separar a las personas del problema: tratar al interlocutor con respeto mientras se ataca el asunto, en lugar de confundir ambas dimensiones. El segundo principio consiste en centrarse en los intereses, no en las posiciones. Detrás de cada demanda concreta subyacen necesidades más profundas, y explorarlas abre alternativas creativas que la postura inicial ocultaba. El tercer principio es generar opciones de beneficio mutuo antes de decidir. Muchas negociaciones fracasan porque las partes asumen que la tarta es fija, cuando un poco de ingenio puede ampliarla. El cuarto principio es insistir en criterios objetivos: apoyarse en precios de mercado, leyes, estándares técnicos o precedentes, de modo que la decisión no dependa del poder relativo de las partes. Fisher y Ury añaden un concepto fundamental: la MAAN, mejor alternativa a un acuerdo negociado. Es decir, qué harás si no llegas a un trato. Conocer tu MAAN te da seguridad y te protege de aceptar cualquier cosa por miedo a salir con las manos vacías. El método se aplica tanto en conflictos familiares y laborales como en relaciones internacionales y ha influido en miles de mediadores profesionales en todo el mundo.', '[{"pregunta":"¿En qué universidad se desarrolló el método?","opciones":["Oxford","Stanford","Harvard","Yale"],"correcta":2},{"pregunta":"¿Cuál es el primer principio?","opciones":["Ceder siempre","Separar a las personas del problema","Ganar a toda costa","Buscar aliados"],"correcta":1},{"pregunta":"¿Qué significa MAAN?","opciones":["Mejor Alternativa a un Acuerdo Negociado","Mejor Análisis de Acciones Nuevas","Modelo Abreviado de Análisis Negociado","Método Avanzado de Acuerdos Naturales"],"correcta":0},{"pregunta":"¿Qué ocurre cuando se asume que la tarta es fija?","opciones":["La negociación fracasa por falta de creatividad","Se acelera el acuerdo","Se multiplican las opciones","Se obtiene más"],"correcta":0}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La salud mental y el estigma', 'Los trastornos de salud mental afectan a una de cada cuatro personas a lo largo de su vida, según estimaciones de la Organización Mundial de la Salud. En la adolescencia y juventud la prevalencia crece por los cambios hormonales, la presión académica y social y la exposición constante a las redes. A pesar de estas cifras, el estigma sigue siendo una barrera que impide a muchas personas buscar ayuda. El estigma se construye con ideas erróneas como que los problemas mentales son signo de debilidad, que la gente que los padece es peligrosa o impredecible, o que basta con poner de su parte para superarlos. Este prejuicio genera dos efectos perjudiciales. El primero es el estigma público, que implica rechazo, discriminación o pérdida de oportunidades laborales al conocerse un diagnóstico. El segundo es el autoestigma, mucho más sutil y dañino: la propia persona interioriza los prejuicios sociales y deja de pedir ayuda por vergüenza. Combatir el estigma pasa por la educación, el contacto con testimonios reales y el lenguaje cuidadoso. Decir persona con depresión en lugar de depresivo humaniza; evitar términos como loco o esquizo como insultos casuales reduce la violencia simbólica. Las personalidades públicas que comparten su experiencia rompen barreras y normalizan el acudir a terapia del mismo modo que se acude al dentista. En Bachillerato, donde empiezan a manifestarse muchos trastornos, crear un entorno donde hablar de salud mental sea natural salva vidas.', '[{"pregunta":"¿A cuántas personas afecta a lo largo de su vida según la OMS?","opciones":["Una de cada diez","Una de cada cuatro","Una de cada dos","Todas"],"correcta":1},{"pregunta":"¿Qué es el autoestigma?","opciones":["La discriminación de los demás","La interiorización de los prejuicios por la propia persona","Una terapia","Un diagnóstico"],"correcta":1},{"pregunta":"¿Qué expresión prefiere el texto?","opciones":["Depresivo","Persona con depresión","Loco","Enfermo mental"],"correcta":1},{"pregunta":"¿Qué ayuda a romper el estigma según el texto?","opciones":["Ocultar los diagnósticos","Personas públicas que comparten su experiencia","Aumentar los medicamentos","Prohibir hablar del tema"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La toma de decisiones vitales', 'Elegir carrera, pareja, ciudad o primer empleo son decisiones vitales que marcan trayectorias a largo plazo. La psicología del comportamiento, desarrollada por investigadores como Daniel Kahneman, ha mostrado que nuestra mente usa dos sistemas de pensamiento. El sistema uno es rápido, intuitivo y emocional; el sistema dos es lento, analítico y reflexivo. Para decisiones cotidianas, el sistema uno funciona bien y ahorra energía mental. Para decisiones vitales, confiar solo en la intuición puede salir caro porque arrastra sesgos invisibles. Los expertos recomiendan un proceso estructurado de varios pasos. Primero, definir con claridad el objetivo y los criterios de decisión; por ejemplo, si eliges carrera, podrías valorar intereses, salidas laborales, nota de corte y distancia al domicilio. Segundo, generar un abanico amplio de opciones sin descartarlas a la primera; pensar más allá del marco obvio suele abrir alternativas interesantes. Tercero, puntuar cada opción frente a cada criterio con un sistema cuantitativo básico que evite dejarse llevar por un único factor emocional. Cuarto, imaginar vívidamente el futuro en la opción preferida y consultar a personas que la hayan recorrido; este paso se llama simulación prospectiva. Quinto, dormir sobre la decisión al menos una noche, porque el cerebro la procesa mientras duermes. Sexto, asumir que ninguna decisión es definitiva: casi todas tienen reversibilidad parcial. Aprender a decidir bien no elimina el riesgo, pero reduce el número de decisiones de las que uno se arrepiente profundamente años más tarde.', '[{"pregunta":"¿Quién describió los dos sistemas de pensamiento?","opciones":["Piaget","Kahneman","Freud","Vygotsky"],"correcta":1},{"pregunta":"¿Cómo es el sistema uno?","opciones":["Lento y analítico","Rápido, intuitivo y emocional","Totalmente consciente","Siempre correcto"],"correcta":1},{"pregunta":"¿En qué consiste la simulación prospectiva?","opciones":["Pedir opinión al azar","Imaginar vívidamente el futuro en la opción preferida","Hacer test psicológicos","Consultar las estrellas"],"correcta":1},{"pregunta":"Según el texto, ninguna decisión es:","opciones":["Definitiva por completo","Buena","Inteligente","Personal"],"correcta":0}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'El estrés crónico y sus efectos', 'El estrés es una respuesta adaptativa del organismo ante una amenaza o desafío. En su forma aguda, resulta útil: el hipotálamo activa el sistema nervioso simpático y libera adrenalina y cortisol, preparando al cuerpo para reaccionar. El problema aparece cuando esta respuesta se mantiene en el tiempo, convirtiéndose en estrés crónico. El cortisol elevado durante meses produce efectos múltiples: deterioro de la memoria y el hipocampo, debilitamiento del sistema inmunitario, alteraciones digestivas, insomnio, aumento de la grasa abdominal y riesgo cardiovascular. También afecta al estado de ánimo, favoreciendo la aparición de ansiedad y depresión. El psicólogo Hans Selye describió en 1936 el síndrome general de adaptación, formado por tres fases. La fase de alarma es la reacción inmediata al estresor. La fase de resistencia es el intento del cuerpo por adaptarse y mantener el rendimiento. La fase de agotamiento llega cuando los recursos se agotan y aparece el colapso físico y psicológico. En Bachillerato, la combinación de carga académica intensa, incertidumbre sobre el futuro y presión social puede empujar al alumnado a la tercera fase. Las estrategias eficaces contra el estrés crónico son conocidas pero requieren constancia: ejercicio aeróbico regular, técnicas de respiración, meditación o mindfulness, sueño suficiente, alimentación equilibrada, contacto social y pausas programadas. La terapia cognitivo-conductual es el tratamiento psicológico con más evidencia científica cuando el estrés interfiere con la vida diaria. Esperar a que pase solo rara vez es una buena idea.', '[{"pregunta":"¿Qué hormona libera el organismo en el estrés agudo?","opciones":["Insulina","Cortisol","Melatonina","Tiroxina"],"correcta":1},{"pregunta":"¿Quién describió el síndrome general de adaptación?","opciones":["Hans Selye","Jean Piaget","Wilhelm Wundt","Erik Erikson"],"correcta":0},{"pregunta":"¿En qué año se describió este síndrome?","opciones":["1916","1936","1956","1986"],"correcta":1},{"pregunta":"¿Qué terapia tiene más evidencia según el texto?","opciones":["Psicoanálisis","Terapia cognitivo-conductual","Hipnosis","Acupuntura"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Los derechos humanos y la ciudadanía global', 'La Declaración Universal de los Derechos Humanos, proclamada por la Asamblea General de la ONU en 1948, fue una respuesta colectiva al horror de la Segunda Guerra Mundial. Sus treinta artículos establecen derechos básicos aplicables a toda persona por el simple hecho de existir, sin distinción de raza, sexo, religión, idioma o condición social. Incluye derechos civiles, como la vida, la libertad o la no discriminación; derechos políticos, como la participación o la libertad de expresión; y derechos económicos, sociales y culturales, como la educación, la salud o un nivel de vida digno. La Declaración no es un tratado vinculante, pero ha inspirado decenas de convenciones posteriores que sí lo son, como el Pacto Internacional de Derechos Civiles y Políticos o la Convención sobre los Derechos del Niño. Pese a su alcance moral, la realidad está lejos de la teoría: en muchas partes del mundo continúan vulneraciones graves, y ningún Estado es plenamente cumplidor. La ciudadanía global es el concepto que propone sentirse parte de una comunidad humana universal con responsabilidades que exceden las fronteras nacionales. Esta actitud no sustituye la ciudadanía local, sino que la amplía: se pueden respetar las tradiciones propias y al mismo tiempo preocuparse por los derechos vulnerados a miles de kilómetros. Informarse, consumir de forma responsable, participar en ONG, denunciar injusticias y votar con conciencia son prácticas concretas de ciudadanía global al alcance de cualquier estudiante de Bachillerato.', '[{"pregunta":"¿En qué año se proclamó la Declaración Universal de los Derechos Humanos?","opciones":["1945","1948","1950","1960"],"correcta":1},{"pregunta":"¿Cuántos artículos tiene?","opciones":["Veinte","Treinta","Cincuenta","Cien"],"correcta":1},{"pregunta":"¿Es vinculante la Declaración?","opciones":["Sí, totalmente","No, pero ha inspirado tratados vinculantes","Solo en Europa","Solo para la ONU"],"correcta":1},{"pregunta":"La ciudadanía global según el texto:","opciones":["Sustituye la ciudadanía local","Amplía la ciudadanía local","Se opone a la local","Solo es para diplomáticos"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'El voto consciente en democracia', 'El derecho al voto se adquiere en España al cumplir los dieciocho años, y muchos estudiantes de segundo de Bachillerato estrenan su ciudadanía política justo antes de la EBAU. Votar es un acto sencillo pero exige responsabilidad para ejercerse con criterio. El voto consciente se apoya en varios pilares. El primero es la información: leer los programas electorales, no solo los titulares o los vídeos virales. Los programas están disponibles en las webs de los partidos y suelen estructurarse por áreas temáticas como economía, educación, sanidad o medio ambiente. El segundo pilar es el contraste: cotejar las promesas con la trayectoria real de cada formación y con análisis de medios con distintas líneas editoriales, no solo los habituales del propio círculo. El tercer pilar es la jerarquización personal: decidir qué temas te importan más y ponderar los programas según esas prioridades, en lugar de votar por simpatía hacia un líder mediático. El cuarto pilar es distinguir entre promesas estructurales creíbles y promesas populistas de difícil cumplimiento. Existen también páginas de fact-checking especializadas que contrastan afirmaciones electorales. La abstención es un derecho legítimo, pero conviene saber que tiene efectos: los partidos se benefician proporcionalmente del voto emitido, y abstenerse equivale a delegar la decisión en quienes sí votan. El voto en blanco y el nulo son opciones intermedias con efectos distintos. Votar con cabeza es una forma profunda de participación democrática, mucho más relevante que opinar en redes sociales.', '[{"pregunta":"¿A qué edad se adquiere el derecho al voto en España?","opciones":["Dieciséis años","Dieciocho años","Veintiuno","Veinticinco"],"correcta":1},{"pregunta":"¿Qué es el primer pilar del voto consciente?","opciones":["La fidelidad al partido","La información","La velocidad","La intuición"],"correcta":1},{"pregunta":"¿Qué efecto tiene la abstención según el texto?","opciones":["Ninguno","Delegar la decisión en quienes sí votan","Anula la elección","Cuenta como voto en blanco"],"correcta":1},{"pregunta":"¿Qué páginas ayudan a contrastar afirmaciones?","opciones":["Blogs de humor","Páginas de fact-checking","Redes de memes","Foros anónimos"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La economía del estudiante universitario', 'Vivir como estudiante universitario implica administrar con inteligencia recursos limitados. Los gastos habituales se dividen en fijos y variables. Los fijos son los que se repiten cada mes: alquiler, matrícula, transporte, seguros, suministros, cuota del móvil, suscripciones. Los variables fluctúan: alimentación, ocio, libros, material, ropa. El primer paso para controlar la economía personal es elaborar un presupuesto realista que parta de los ingresos disponibles, ya sean ahorros, ayudas familiares, becas o trabajo propio, y distribuya cada euro antes de gastarlo. Una regla sencilla muy usada es la fifty-thirty-twenty: el cincuenta por ciento para necesidades, el treinta para gastos personales y el veinte para ahorro o amortización de deuda. En la vida estudiantil hay ajustes: si se dispone de menos ingresos, el porcentaje de ocio suele reducirse. Existen estrategias eficaces para ahorrar sin sufrir. Comprar libros de segunda mano o alquilarlos en bibliotecas universitarias reduce considerablemente el gasto en material. Cocinar en casa y preparar comidas para el resto de la semana es mucho más barato que comer fuera. Compartir piso y transporte divide costes. Aprovechar descuentos estudiantiles en ocio, software, gimnasios, museos o cine multiplica experiencias sin vaciar la cartera. Es importante también construir un pequeño fondo de emergencia para imprevistos como una avería del portátil o un billete inesperado a casa. Llevar un registro mensual en una hoja de cálculo, aunque sea sencillo, convierte cifras abstractas en decisiones concretas y evita sorpresas a final de mes.', '[{"pregunta":"¿Cuáles son los gastos fijos?","opciones":["Los que cambian cada mes","Los que se repiten cada mes","Los de ocio","Los de ropa"],"correcta":1},{"pregunta":"¿En qué consiste la regla fifty-thirty-twenty?","opciones":["Cincuenta por ciento para ocio","Cincuenta necesidades, treinta personal, veinte ahorro","Cincuenta en libros","Cincuenta para viajar"],"correcta":1},{"pregunta":"¿Para qué sirve el fondo de emergencia?","opciones":["Comprar caprichos","Cubrir imprevistos como una avería del portátil","Pagar las vacaciones","Invertir en bolsa"],"correcta":1},{"pregunta":"Según el texto, llevar un registro mensual:","opciones":["Es una pérdida de tiempo","Convierte cifras abstractas en decisiones concretas","Solo sirve en empresas","Exige software caro"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Ética digital e inteligencia artificial', 'La irrupción masiva de la inteligencia artificial generativa ha planteado dilemas éticos que apenas existían hace unos años. Herramientas como los modelos de lenguaje permiten escribir textos, resolver problemas o diseñar imágenes en segundos, lo que tiene aplicaciones positivas pero también usos problemáticos. En el ámbito académico, uno de los debates más vivos es el uso de estas herramientas para hacer trabajos o exámenes. ¿Es plagio pedir a una IA que redacte un ensayo y entregarlo como propio? Las universidades están actualizando sus normativas y, en general, consideran fraude presentar como propio un contenido que no se ha elaborado personalmente. Usar la IA como asistente para corregir, traducir o generar ideas suele aceptarse, siempre que se reconozca. La regla orientadora es la transparencia: declarar cuándo y cómo se ha usado una herramienta. Más allá del ámbito académico, la ética digital incluye otros problemas. Las imágenes generadas por IA pueden crear deepfakes que suplantan a personas reales sin su consentimiento, con consecuencias graves para la dignidad y la privacidad. Los sesgos presentes en los datos de entrenamiento pueden trasladarse a las respuestas, perpetuando discriminaciones históricas. El consumo energético de los grandes modelos tiene una huella ambiental considerable. Ante este panorama, la ciudadanía necesita una alfabetización crítica que permita usar estas herramientas con criterio, evaluando sus respuestas, citando cuando proceda y rechazando aplicaciones abusivas. La tecnología por sí sola no es buena ni mala: depende del marco ético y regulatorio en que se utilice.', '[{"pregunta":"¿Qué consideran las universidades en general?","opciones":["Que la IA es siempre aceptable","Que presentar como propio un contenido generado por IA es fraude","Que la IA no existe","Que no hay que citar fuentes"],"correcta":1},{"pregunta":"¿Qué son los deepfakes?","opciones":["Noticias verdaderas","Imágenes generadas por IA que suplantan a personas reales","Programas educativos","Videojuegos"],"correcta":1},{"pregunta":"¿Qué regla orientadora se propone?","opciones":["El secreto","La transparencia","La velocidad","La creatividad"],"correcta":1},{"pregunta":"Según el texto, la tecnología:","opciones":["Es siempre buena","Depende del marco ético y regulatorio en que se usa","Es siempre mala","Es neutra en todos los casos"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Las entrevistas para acceder a la universidad', 'Algunas carreras universitarias y casi todos los estudios en universidades privadas o extranjeras incluyen una entrevista personal dentro del proceso de admisión. Esta conversación, que suele durar entre veinte y cuarenta minutos, permite a los tribunales evaluar aspectos que las notas no revelan: vocación, madurez, capacidad de expresión y de argumentación, motivación y ajuste con la cultura de la institución. Prepararse para estas entrevistas exige tiempo y método. El primer paso es investigar a fondo la universidad: historia, valores, programa, profesores destacados, actividades extraacadémicas. Demostrar conocimiento concreto del lugar al que uno aspira marca la diferencia con quien aplica de forma genérica. El segundo paso es anticipar preguntas típicas y preparar respuestas auténticas, no memorizadas: por qué esta carrera, por qué esta universidad, qué te diferencia, una dificultad que hayas superado, un libro que te haya marcado. Ensayar con alguien de confianza, grabarse en vídeo y revisar el lenguaje no verbal resulta muy útil. El tercer paso es preparar dos o tres preguntas propias para el entrevistador, porque demuestran interés genuino y aportan información valiosa. Durante la entrevista, conviene saludar con firmeza, mantener contacto visual, escuchar antes de responder, estructurar las respuestas con ejemplos concretos y mostrar una actitud positiva sin exagerar. Al acabar, agradecer el tiempo dedicado y pedir, si procede, los plazos siguientes. Enviar un breve correo de agradecimiento horas después causa una excelente impresión sin resultar intrusivo.', '[{"pregunta":"¿Cuánto suelen durar estas entrevistas?","opciones":["Cinco minutos","Entre veinte y cuarenta minutos","Dos horas","Un día entero"],"correcta":1},{"pregunta":"¿Qué es lo primero que se recomienda?","opciones":["Estudiar solo","Investigar a fondo la universidad","Memorizar respuestas","Vestir de forma extravagante"],"correcta":1},{"pregunta":"¿Por qué conviene preparar preguntas propias?","opciones":["Para intimidar al tribunal","Porque demuestran interés genuino","Para alargar la entrevista","Porque es obligatorio"],"correcta":1},{"pregunta":"¿Qué causa buena impresión al acabar?","opciones":["No hacer nada","Un breve correo de agradecimiento","Llamar al tribunal","Enviar un regalo"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'El Erasmus y la movilidad europea', 'El programa Erasmus, creado en 1987 por la Comunidad Europea, ha facilitado que millones de jóvenes cursen un periodo de sus estudios en otra universidad del continente. Lleva el nombre del humanista Erasmo de Rotterdam, viajero y defensor del intercambio cultural. Desde su lanzamiento, el programa se ha ampliado a través de sucesivas fases, culminando en el actual Erasmus plus, que incluye movilidad entre países asociados no europeos y prácticas profesionales en empresas extranjeras. Los beneficios van mucho más allá del aspecto académico. La experiencia de adaptarse a una cultura distinta, gestionar la vida cotidiana en otro idioma, forjar amistades internacionales y ampliar la visión del mundo produce un crecimiento personal difícil de replicar en clase. Estudios posteriores muestran que los erasmus tienen mejores oportunidades laborales y una red profesional más amplia. Sin embargo, la experiencia también plantea retos. El choque cultural inicial puede generar ansiedad y sentimiento de aislamiento, especialmente en las primeras semanas. Los trámites administrativos exigen anticipación: elegir universidad destino, cumplimentar el acuerdo académico, tramitar seguro médico europeo, buscar alojamiento, convalidar asignaturas. Conviene empezar los trámites al menos seis meses antes de la partida y acudir a las sesiones informativas del servicio de relaciones internacionales. Finalmente, el Erasmus exige una dosis extra de autonomía económica y emocional. Quien la afronta con espíritu abierto y planificación realista suele volver transformado, con una confianza nueva en su capacidad de afrontar retos complejos en entornos desconocidos.', '[{"pregunta":"¿En qué año se creó el programa Erasmus?","opciones":["1977","1987","1997","2007"],"correcta":1},{"pregunta":"¿A quién rinde homenaje el nombre?","opciones":["Al filósofo Erasmo de Rotterdam","A un político europeo","A un científico alemán","A un papa"],"correcta":0},{"pregunta":"¿Cuándo conviene empezar los trámites?","opciones":["Una semana antes","Un mes antes","Al menos seis meses antes","Al llegar al destino"],"correcta":2},{"pregunta":"¿Qué beneficio profesional mencionan los estudios?","opciones":["Mejores oportunidades laborales y mayor red profesional","Salarios garantizados","Trabajos vitalicios","Contratos automáticos"],"correcta":0}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La ética del trabajo en equipo', 'En la universidad y en el mundo laboral, el trabajo en equipo es la norma más que la excepción. Dominarlo exige habilidades que van más allá del contenido técnico y que a menudo distinguen a los profesionales más valorados. La ética del trabajo en equipo se basa en varios principios. El primero es la responsabilidad compartida: aceptar la parte proporcional del éxito o el fracaso sin culpar a los demás. El segundo es la transparencia: informar sobre los avances, los bloqueos y los errores sin ocultarlos hasta el último momento. El tercero es la puntualidad en los compromisos; incumplir plazos perjudica a todo el grupo y erosiona la confianza. El cuarto es el reconocimiento: mencionar públicamente las aportaciones ajenas sin apropiarse del mérito. El quinto es la gestión constructiva del desacuerdo: criticar las ideas con argumentos y no atacar a las personas. Un fenómeno clásico del trabajo en equipo es la pereza social, descrita por el ingeniero francés Max Ringelmann a finales del siglo XIX. Observó que el esfuerzo individual disminuye cuando el grupo crece, porque cada miembro asume que los otros compensarán su falta. Combatir este fenómeno exige roles claros, tareas individualizables y métricas visibles. Otra trampa frecuente es el pensamiento grupal, descrito por Irving Janis, que lleva a consensos rápidos sin pensamiento crítico. Nombrar un abogado del diablo explícito que cuestione las decisiones es una técnica útil. Aprender a trabajar en equipo en Bachillerato es una inversión que rentabiliza durante toda la vida profesional.', '[{"pregunta":"¿En qué consiste la pereza social?","opciones":["Dormir durante las reuniones","El esfuerzo individual disminuye al crecer el grupo","No hacer deporte","Llegar tarde siempre"],"correcta":1},{"pregunta":"¿Quién describió la pereza social?","opciones":["Max Ringelmann","Irving Janis","Kurt Lewin","Elton Mayo"],"correcta":0},{"pregunta":"¿Qué describió Irving Janis?","opciones":["La pereza social","El pensamiento grupal","La inteligencia emocional","La disonancia cognitiva"],"correcta":1},{"pregunta":"¿Qué técnica sirve contra el pensamiento grupal?","opciones":["Votar en secreto","Nombrar un abogado del diablo","Callar en las reuniones","Hacer lluvias de ideas eternas"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La meditación y el mindfulness', 'El mindfulness o atención plena es una práctica procedente de tradiciones orientales adaptada al contexto occidental por el biólogo Jon Kabat-Zinn, quien en 1979 creó el programa de reducción del estrés basado en la atención plena en la Universidad de Massachusetts. Consiste en prestar atención deliberada al momento presente sin juicio, observando pensamientos, sensaciones y emociones tal como aparecen, sin enredarse en ellos. Décadas de investigación han documentado beneficios medibles: reducción del estrés, mejora del sueño, mayor concentración, disminución de la rumiación y aumento del bienestar subjetivo. También se han observado cambios en la actividad cerebral: menor reactividad de la amígdala y mayor conexión entre las áreas de la atención. La práctica más sencilla consiste en sentarse cómodamente durante diez o quince minutos, cerrar los ojos, llevar la atención a la respiración y, cuando la mente se distraiga, devolverla con suavidad al aire que entra y sale. No se trata de dejar la mente en blanco, objetivo imposible, sino de entrenar la capacidad de observar sin engancharse. Existen aplicaciones como Headspace, Calm o Petit Bambou que guían sesiones graduadas para principiantes. A los resultados físicos y mentales se añade un beneficio filosófico más profundo: descubrir que uno no es sus pensamientos, sino el observador de estos. Esta toma de distancia alivia la tiranía mental y permite respuestas más libres. Para estudiantes de Bachillerato con presión académica, quince minutos diarios pueden marcar una diferencia notable en calma y claridad.', '[{"pregunta":"¿Quién creó el programa MBSR?","opciones":["Dalai Lama","Jon Kabat-Zinn","Thich Nhat Hanh","Eckhart Tolle"],"correcta":1},{"pregunta":"¿En qué año lo creó?","opciones":["1969","1979","1989","1999"],"correcta":1},{"pregunta":"¿En qué consiste la práctica básica?","opciones":["Dejar la mente en blanco","Llevar la atención a la respiración y devolverla con suavidad cuando se distrae","Dormir","Repetir un mantra en voz alta"],"correcta":1},{"pregunta":"¿Qué cambio cerebral se ha observado?","opciones":["Mayor reactividad de la amígdala","Menor reactividad de la amígdala","Desaparición del hipocampo","Crecimiento del cerebelo"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Sostenibilidad y huella ecológica individual', 'La huella ecológica es un indicador que estima la superficie de tierra y agua necesaria para producir los recursos que consume una persona y absorber los residuos que genera. El concepto fue desarrollado por Mathis Wackernagel y William Rees en los años noventa. Se expresa en hectáreas globales y permite comparar individuos, países o modos de vida. Los datos son contundentes: si toda la humanidad viviera al estilo medio europeo, haría falta casi el triple de planetas para sostener el consumo. El día del rebasamiento terrestre marca la fecha anual en la que hemos consumido los recursos que la Tierra puede regenerar en un año; en las últimas décadas este día se adelanta progresivamente y en 2023 cayó en agosto. Reducir la huella ecológica personal es más fácil de lo que parece si se actúa en las áreas con mayor impacto. La alimentación supone casi un tercio: reducir el consumo de carne, especialmente de rumiantes, y comer productos de temporada y de proximidad tiene un efecto notable. El transporte es otro eje clave: caminar, usar la bicicleta o el transporte público sustituye viajes en coche con elevado coste ambiental. El consumo energético doméstico se reduce con electrodomésticos eficientes, bajar la calefacción un par de grados y apagar lo que no se usa. El consumo responsable, comprar menos ropa barata y más duradera, priorizar reparar sobre tirar, evitar el plástico de un solo uso, completa el conjunto. Los gestos individuales no resuelven el problema por sí solos, pero suman.', '[{"pregunta":"¿Quiénes desarrollaron el concepto de huella ecológica?","opciones":["Rachel Carson y Al Gore","Wackernagel y Rees","Greta Thunberg y David Attenborough","Jane Goodall y Vandana Shiva"],"correcta":1},{"pregunta":"¿Qué es el día del rebasamiento terrestre?","opciones":["El día más caluroso del año","La fecha en la que hemos consumido los recursos regenerables anuales","El inicio de la primavera","El fin del verano"],"correcta":1},{"pregunta":"¿Qué área representa casi un tercio del impacto?","opciones":["La alimentación","El turismo","La ropa","El agua"],"correcta":0},{"pregunta":"¿Qué tipo de carne tiene mayor impacto?","opciones":["La de rumiantes","La de ave","La de pescado","Todas igual"],"correcta":0}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'El duelo y la pérdida', 'El duelo es la respuesta natural a una pérdida significativa: la muerte de un ser querido, pero también una ruptura, un cambio de ciudad, la pérdida de una amistad o de un proyecto vital. La psiquiatra Elisabeth Kübler-Ross describió en 1969 cinco fases clásicas: negación, ira, negociación, depresión y aceptación. Aunque posteriores investigaciones han matizado que estas fases no se suceden en orden lineal ni todo el mundo atraviesa todas, siguen siendo una guía útil para reconocer emociones que parecen contradictorias o inapropiadas. El duelo no es una enfermedad: es un proceso adaptativo que requiere tiempo y suele durar entre seis meses y dos años. Durante este periodo aparecen síntomas normales como tristeza profunda, dificultad para concentrarse, cambios en el apetito, sueños del ausente o sensación de vacío. También pueden surgir emociones menos aceptadas socialmente como el alivio, la culpa o incluso la rabia hacia quien se ha ido. Reconocerlas sin juzgarse es parte del trabajo. Las estrategias que ayudan son conocidas: hablar con personas de confianza, expresar lo que se siente mediante escritura o arte, cuidar el cuerpo con rutinas de sueño y ejercicio, permitirse llorar, evitar tomar decisiones importantes los primeros meses y pedir ayuda profesional si aparece riesgo grave o si el duelo se cronifica. Los grupos de apoyo ofrecen un espacio donde compartir con personas que pasan por situaciones similares. El paso del tiempo no cura completamente la pérdida, pero permite seguir viviendo con ella sin quedarse atrapado.', '[{"pregunta":"¿Quién describió las cinco fases del duelo?","opciones":["Elisabeth Kübler-Ross","Sigmund Freud","Anna Freud","Carl Rogers"],"correcta":0},{"pregunta":"¿Cuánto suele durar el duelo?","opciones":["Una semana","Entre seis meses y dos años","Un mes","Diez años"],"correcta":1},{"pregunta":"¿Qué recomienda el texto sobre las decisiones importantes?","opciones":["Tomarlas rápido para avanzar","Evitarlas los primeros meses","Delegarlas a la familia","Aplazarlas diez años"],"correcta":1},{"pregunta":"Según el texto, el duelo es:","opciones":["Una enfermedad que hay que curar","Un proceso adaptativo","Un fallo del sistema","Una elección personal"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Las relaciones afectivas maduras', 'Las relaciones de pareja maduras se construyen sobre cuatro pilares que investigadores como John Gottman han identificado tras décadas de estudio con miles de parejas. El primer pilar es el respeto mutuo, que se traduce en aceptar al otro tal como es, valorar sus diferencias y tratarlo con consideración incluso en los desacuerdos. El segundo pilar es la confianza, entendida como la creencia firme en la buena intención del otro. Se construye con pequeños actos cotidianos, no con grandes declaraciones. El tercer pilar es la comunicación honesta, que incluye expresar necesidades, establecer límites y resolver conflictos sin recurrir al silencio prolongado o al sarcasmo hiriente. El cuarto pilar es el compromiso, la decisión consciente de priorizar la relación incluso cuando aparecen tentaciones o momentos bajos. Gottman identificó también cuatro actitudes que predicen con alta fiabilidad el fracaso: la crítica constante, el desprecio, la actitud defensiva y la evasión. Las llamó los cuatro jinetes del apocalipsis relacional. Su presencia no sentencia la relación, pero exige intervención. Hay señales que distinguen una relación sana de una tóxica. Una relación sana permite crecer individualmente mientras se construye un proyecto común. Una relación tóxica aísla, desgasta la autoestima, genera miedo a expresarse o control excesivo sobre amistades, ropa o redes sociales. Reconocer estas señales temprano evita desgastes mayores. Pedir ayuda profesional cuando aparecen patrones dañinos no es una debilidad: muchas parejas salen reforzadas tras una terapia. Y, si la relación no es viable, saber soltar también es madurez.', '[{"pregunta":"¿Quién identificó los cuatro pilares?","opciones":["Erich Fromm","John Gottman","David Schnarch","Esther Perel"],"correcta":1},{"pregunta":"¿Cuáles son los cuatro jinetes del apocalipsis relacional?","opciones":["Crítica, desprecio, actitud defensiva y evasión","Celos, miedo, rabia y culpa","Mentira, trampa, engaño y robo","Soledad, tristeza, ira y miedo"],"correcta":0},{"pregunta":"¿Qué caracteriza una relación tóxica según el texto?","opciones":["Genera crecimiento mutuo","Aísla y desgasta la autoestima","Fomenta amistades","Permite discrepar libremente"],"correcta":1},{"pregunta":"Pedir ayuda profesional es signo de:","opciones":["Debilidad","No es debilidad, muchas parejas salen reforzadas","Fracaso definitivo","Moda"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La procrastinación crónica', 'La procrastinación es el hábito de aplazar voluntariamente tareas importantes, a sabiendas de que el retraso empeorará la situación. No se trata de pereza, como suele creerse, sino de una dificultad para gestionar las emociones negativas que ciertas tareas suscitan. El investigador canadiense Timothy Pychyl ha demostrado que la procrastinación es, en esencia, una estrategia de regulación emocional a corto plazo: huir del malestar posponiendo aquello que lo genera. El problema es que esta huida alimenta un círculo vicioso: el retraso aumenta la ansiedad, la ansiedad hace más aversiva la tarea y el cerebro vuelve a procrastinar. Los desencadenantes más frecuentes son el perfeccionismo, el miedo al fracaso, la ambigüedad sobre cómo empezar y la falta de sentido percibido. Las estrategias eficaces contra la procrastinación crónica combinan varias técnicas. La regla de los dos minutos sugiere comenzar la tarea durante solo dos minutos para romper la resistencia inicial; con frecuencia, una vez iniciada, se continúa. Fraccionar grandes proyectos en microtareas concretas hace que cada paso sea abordable sin la parálisis del todo. Usar técnicas como la Pomodoro, que alterna veinticinco minutos de foco con cinco de descanso, ayuda a sostener la concentración. Reducir las distracciones digitales con aplicaciones como Forest o Cold Turkey elimina tentaciones. Finalmente, practicar la autocompasión es decisivo: los estudios muestran que perdonarse por haber procrastinado reduce la probabilidad de volver a hacerlo, mientras que castigarse la aumenta. Reconocer que el problema es emocional, no de tiempo, abre el camino a soluciones reales.', '[{"pregunta":"¿Quién ha investigado la procrastinación desde el enfoque emocional?","opciones":["Timothy Pychyl","Stephen Covey","Cal Newport","David Allen"],"correcta":0},{"pregunta":"¿Qué es la procrastinación según el texto?","opciones":["Pereza","Una estrategia de regulación emocional a corto plazo","Inteligencia","Trabajar en exceso"],"correcta":1},{"pregunta":"¿En qué consiste la regla de los dos minutos?","opciones":["Hacer la tarea en dos minutos","Comenzar la tarea durante solo dos minutos","Dormir dos minutos antes","Esperar dos minutos"],"correcta":1},{"pregunta":"Qué efecto tiene castigarse por procrastinar?","opciones":["Reducir la procrastinación","Aumentar la procrastinación","Ningún efecto","Curarla"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Iniciar un proyecto personal', 'Muchos estudiantes sueñan con emprender un proyecto personal durante o después de Bachillerato: un canal de contenidos, una pequeña empresa, una ONG, un club deportivo, una app, una iniciativa artística. Dar el paso exige superar varios obstáculos mentales. El primero es el perfeccionismo: querer que todo esté listo antes de lanzar. La filosofía lean startup, popularizada por Eric Ries, propone lo contrario: publicar cuanto antes un producto mínimo viable, recoger feedback real y mejorarlo de forma iterativa. El segundo obstáculo es el miedo al juicio ajeno, que se combate recordando que la mayoría de la gente está ocupada con sus propios proyectos y apenas presta atención al resto. El tercer obstáculo es la falta de claridad sobre el primer paso; aquí ayuda definir una acción concreta para los siguientes siete días y ejecutarla sin esperar a tener todo resuelto. Los proyectos personales ofrecen beneficios que van más allá del resultado directo. Enseñan a gestionar tiempo, dinero, imprevistos, colaboradores y expectativas. Generan contenido concreto para el currículum y las entrevistas. Fortalecen la identidad y el sentido de agencia, la sensación de ser protagonista de la propia vida. Los errores forman parte del aprendizaje y no son fracasos a evitar: cada obstáculo enseña algo que los manuales no pueden transmitir. Es recomendable elegir proyectos alineados con intereses auténticos y no con modas, porque la constancia necesaria a medio plazo exige motivación intrínseca. Empezar pequeño, documentar el proceso y celebrar los pequeños avances son hábitos que sostienen la iniciativa cuando aparecen las dudas inevitables.', '[{"pregunta":"¿Qué filosofía popularizó Eric Ries?","opciones":["Lean startup","Six sigma","Agile","Kaizen"],"correcta":0},{"pregunta":"¿Qué propone la filosofía lean?","opciones":["Esperar a la perfección","Publicar cuanto antes un producto mínimo viable","No lanzar nunca","Invertir millones primero"],"correcta":1},{"pregunta":"Según el texto, los proyectos personales enseñan:","opciones":["A gestionar tiempo, dinero y expectativas","Exclusivamente a ganar dinero","Solo a dibujar","Solo a programar"],"correcta":0},{"pregunta":"¿Por qué elegir proyectos alineados con intereses auténticos?","opciones":["Porque son más rentables","Porque la constancia necesaria exige motivación intrínseca","Porque son más fáciles","Porque los aprueban los profesores"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Los sesgos en el lenguaje', 'El lenguaje no es un simple vehículo neutral: refleja y refuerza la manera en que pensamos el mundo. Numerosos estudios de psicolingüística han mostrado que las palabras que utilizamos influyen en percepciones, decisiones y actitudes. El sesgo de género en el lenguaje es uno de los más estudiados: hablar siempre en masculino genérico tiende a invisibilizar a las mujeres en la imagen mental que forma quien escucha. Experimentos con niños a los que se les pide dibujar a un científico o a un médico muestran que la mayoría dibuja hombres, una prueba del peso de los estereotipos lingüísticos. Otros sesgos son más sutiles. El lenguaje belicista aplicado a la enfermedad, como vencer al cáncer o perder la batalla, culpabiliza al paciente por su deterioro físico, como si no haberse esforzado lo suficiente fuera un fracaso personal. El lenguaje pasivo en la violencia, del tipo fue asesinada o sufrió maltrato, borra al agresor del relato. La expresión persona con discapacidad antepone al ser humano a su condición, mientras que discapacitado la convierte en etiqueta definitoria. Cuidar el lenguaje no es censura ni purismo: es un ejercicio de precisión y empatía. En Bachillerato, donde se consolidan hábitos discursivos para la vida adulta, conviene reflexionar sobre las palabras que se usan y sobre las que se evitan. Preguntarse a quién excluye o a quién representa una determinada formulación es un primer paso sencillo para escribir y hablar con mayor conciencia y justicia.', '[{"pregunta":"¿Qué refleja el lenguaje según el texto?","opciones":["Solo sonidos","Cómo pensamos el mundo","Solo letras","Nada importante"],"correcta":1},{"pregunta":"¿Qué problema tiene el lenguaje belicista aplicado a la enfermedad?","opciones":["Es muy formal","Culpabiliza al paciente por su deterioro","Es imposible de usar","Es gracioso"],"correcta":1},{"pregunta":"¿Qué expresión prefiere el texto?","opciones":["Discapacitado","Persona con discapacidad","Minusválido","Inválido"],"correcta":1},{"pregunta":"Cuidar el lenguaje es:","opciones":["Censura","Un ejercicio de precisión y empatía","Purismo inútil","Una moda pasajera"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'El consentimiento en las relaciones', 'El consentimiento es un concepto central en cualquier relación sana, especialmente en el terreno afectivo y sexual. En España, la ley orgánica de 2022 consagró el principio de que solo el sí es sí, dejando claro que la ausencia de un no explícito no equivale a un consentimiento válido. El consentimiento válido cumple varios requisitos. Debe ser libre, sin coacciones, amenazas ni aprovechamiento de una situación de vulnerabilidad, como la intoxicación o el miedo. Debe ser informado, de modo que ambas partes sepan a qué están accediendo concretamente. Debe ser específico para cada acto: aceptar una cosa no implica aceptar otras. Debe ser revocable en cualquier momento: nadie está obligado a continuar por haber empezado. Y debe ser entusiasta, expresado por palabras o gestos inequívocos, no deducido de silencios, pasividad o presión ambiental. Enseñar y practicar el consentimiento desde la adolescencia reduce significativamente las agresiones, los malentendidos y los traumas. En el ámbito digital, el consentimiento también implica no compartir imágenes íntimas de otras personas sin su permiso, un delito tipificado en muchos países. Pedir consentimiento no rompe la magia del momento, como a veces se afirma: al contrario, refuerza el respeto y la complicidad. Preguntar en voz alta, observar el lenguaje corporal, estar atento a las señales sutiles y detenerse ante cualquier duda son hábitos maduros. Educar en consentimiento no es solo prevenir delitos: es construir una cultura afectiva basada en el respeto mutuo y la responsabilidad compartida.', '[{"pregunta":"¿Qué principio consagró la ley orgánica española de 2022?","opciones":["Solo el sí es sí","Quien calla otorga","El no significa quizá","La duda es aceptación"],"correcta":0},{"pregunta":"¿Qué significa que el consentimiento sea revocable?","opciones":["Que se puede retirar en cualquier momento","Que es permanente","Que dura un año","Que lo firma un notario"],"correcta":0},{"pregunta":"¿Cómo debe ser expresado el consentimiento?","opciones":["Por deducción","Entusiasta, por palabras o gestos inequívocos","Por silencio","Por escrito solo"],"correcta":1},{"pregunta":"Compartir imágenes íntimas sin permiso es:","opciones":["Legal","Un delito tipificado en muchos países","Una broma","Un derecho"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'La vida después del instituto', 'Terminar el instituto marca el cierre de una etapa larga y significativa. Durante doce o trece años, la rutina escolar ha estructurado el calendario, el grupo de iguales y buena parte de la identidad. Al acabar, se abre un espacio nuevo cargado de posibilidades y también de incertidumbre. Algunos estudiantes empezarán la universidad en septiembre, otros iniciarán un ciclo formativo superior, otros comenzarán a trabajar o se tomarán un año sabático para viajar, aprender idiomas o probar proyectos. No existe un camino único ni un calendario obligatorio: lo importante es avanzar con propósito y flexibilidad. Los psicólogos hablan de la transición a la adultez emergente, un periodo descrito por Jeffrey Arnett que se sitúa entre los dieciocho y los veintinueve años, caracterizado por exploraciones, cambios de dirección y sensación de estar entre dos mundos. Es normal sentir vértigo, nostalgia por lo que se deja atrás y cierto miedo al futuro. También es normal que los grupos de amigos del instituto se dispersen; algunas amistades perdurarán y otras se difuminarán sin que eso signifique un fracaso. Los consejos más recurrentes de quienes ya han pasado la transición son varios. Mantener rutinas básicas de sueño, ejercicio y alimentación. Salir de la zona de confort sin precipitarse. No compararse con los compañeros cuyas elecciones son distintas. Pedir ayuda cuando aparezcan dificultades. Cuidar las relaciones familiares que siguen siendo un sostén. Recordar que los primeros seis meses fuera del entorno conocido son los más duros y que casi siempre se superan.', '[{"pregunta":"¿Cómo llamó Jeffrey Arnett a esta transición?","opciones":["Adultez emergente","Juventud prolongada","Adolescencia tardía","Madurez precoz"],"correcta":0},{"pregunta":"¿Entre qué edades la sitúa?","opciones":["Entre quince y dieciocho","Entre dieciocho y veintinueve","Entre veinte y veinticinco","Entre treinta y cuarenta"],"correcta":1},{"pregunta":"Según el texto, los primeros seis meses fuera del entorno conocido son:","opciones":["Los más fáciles","Los más duros","Los más caros","Los más cortos"],"correcta":1},{"pregunta":"¿Qué dice el texto sobre las amistades del instituto?","opciones":["Todas perduran para siempre","Algunas perduran, otras se difuminan sin ser un fracaso","Siempre se rompen","No importan"],"correcta":1}]'::jsonb),

('tutoria', 'bachillerato', '{2}', 'Libertad, responsabilidad y proyecto de vida', 'El filósofo existencialista Jean-Paul Sartre afirmó que los seres humanos estamos condenados a ser libres. Con esta frase paradójica quería decir que, incluso cuando quisiéramos evitarlo, no podemos dejar de elegir: incluso no elegir es una elección. Esta libertad radical conlleva una responsabilidad igualmente radical; cada persona es autora de su propia vida y no puede descargar las decisiones importantes en la tradición, la familia o las circunstancias. La idea, aunque exigente, resulta liberadora cuando se entiende bien: no estamos determinados por el pasado y podemos reinventarnos en cualquier momento. Construir un proyecto de vida es el ejercicio práctico de asumir esa libertad. Implica preguntarse qué tipo de persona se quiere llegar a ser, qué valores se quieren encarnar, qué contribución se quiere aportar al mundo y qué experiencias se quieren vivir. No se trata de definir un plan rígido, sino de establecer una brújula que oriente decisiones importantes. Los expertos en coaching proponen ejercicios como escribir una carta a uno mismo diez años en el futuro, redactar el propio epitafio o imaginar un día perfecto dentro de quince años. Estos ejercicios revelan prioridades a menudo ocultas. El proyecto de vida debe revisarse periódicamente, porque las personas cambiamos y lo que parecía esencial a los dieciocho puede dejar de serlo a los veinticinco. Lo importante no es acertar a la primera, sino mantener la conversación con uno mismo abierta, honesta y sostenida a lo largo de los años.', '[{"pregunta":"¿Qué afirmó Sartre sobre los seres humanos?","opciones":["Que somos esclavos","Que estamos condenados a ser libres","Que somos indiferentes","Que somos infalibles"],"correcta":1},{"pregunta":"¿Qué implica construir un proyecto de vida?","opciones":["Definir un plan rígido","Establecer una brújula orientadora","Obedecer a la familia","Dejarse llevar"],"correcta":1},{"pregunta":"¿Qué ejercicio proponen los expertos?","opciones":["Escribir una carta a uno mismo en el futuro","Memorizar un manual","Hacer un examen","Repetir un mantra"],"correcta":0},{"pregunta":"Según el texto, el proyecto de vida debe:","opciones":["Cumplirse al pie de la letra","Revisarse periódicamente","Mantenerse en secreto","Fijarse para toda la vida"],"correcta":1}]'::jsonb);
